

/* ── Theme Toggle Logic ── */
function toggleTheme() {
  const body = document.body;
  const btn = document.getElementById('themeBtn');
  body.classList.toggle('dark-mode');
  
  const isDark = body.classList.contains('dark-mode');
  
  if (isDark) {
    // Sun Icon for Light Mode
    btn.innerHTML = `<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="5"/><line x1="12" y1="1" x2="12" y2="3"/><line x1="12" y1="21" x2="12" y2="23"/><line x1="4.22" y1="4.22" x2="5.64" y2="5.64"/><line x1="18.36" y1="18.36" x2="19.78" y2="19.78"/><line x1="1" y1="12" x2="3" y2="12"/><line x1="21" y1="12" x2="23" y2="12"/><line x1="4.22" y1="19.78" x2="5.64" y2="18.36"/><line x1="18.36" y1="5.64" x2="19.78" y2="4.22"/></svg> Light`;
    localStorage.setItem('theme', 'dark');
  } else {
    // Moon Icon for Dark Mode
    btn.innerHTML = `<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"></path></svg> Dark`;
    localStorage.setItem('theme', 'light');
  }
}

// Check local storage on initial load
if (localStorage.getItem('theme') === 'dark') {
  document.body.classList.add('dark-mode');
  document.getElementById('themeBtn').innerHTML = `<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="5"/><line x1="12" y1="1" x2="12" y2="3"/><line x1="12" y1="21" x2="12" y2="23"/><line x1="4.22" y1="4.22" x2="5.64" y2="5.64"/><line x1="18.36" y1="18.36" x2="19.78" y2="19.78"/><line x1="1" y1="12" x2="3" y2="12"/><line x1="21" y1="12" x2="23" y2="12"/><line x1="4.22" y1="19.78" x2="5.64" y2="18.36"/><line x1="18.36" y1="5.64" x2="19.78" y2="4.22"/></svg> Light`;
}










const DATA = [{"n": "1", "t": "Name and territory of the Union", "c": "(1) India, that is Bharat, shall be a Union of States. [(2) The States and the territories thereof shall be as specified in the First Schedule.] (3) The territory of India shall comprise— (a) the territories of the States*; [(b) the Union territories specified in the First Schedule; and] (c) such other territories as may be acquired.", "p": "I", "pn": "The Union and its Territory", "clr": "#E8A838"}, {"n": "2", "t": "Admission or Establishment of new States", "c": "Parliament may by law admit into the Union, or establish, new States on such terms and conditions as it thinks fit. 2A. [Sikkim to be associated with the Union.] Omitted by the Constitution (Thirty-sixth Amendment) Act, 1975, s.5 (w.e.f. 26.4.1975).", "p": "I", "pn": "The Union and its Territory", "clr": "#E8A838"}, {"n": "3", "t": "Formation of new States and alteration of areas, boundaries or names of existing", "c": "States:- Parliament may by law— (a) form a new State by separation of territory from any State or by uniting two or more States or parts of States or by uniting any territory to a part of any State; (b) increase the area of any State; (c) diminish the area of any State; (d) alter the boundaries of any State; (e) alter the name of any State:", "p": "I", "pn": "The Union and its Territory", "clr": "#E8A838"}, {"n": "4", "t": "Laws made under articles 2 and 3 to provide for the amendment of the First and", "c": "the Fourth Schedules and supplemental, incidental and consequential matters:- (1) Any law referred to in article 2 or article 3 shall contain such provisions for the amendment of the First Schedule and the Fourth Schedule as may be necessary to give effect to the provisions of the law and may also contain such supplemental, incidental and consequential provisions (including provisions as to representation in Parliament and in the Legislature or Legislatures of the State or States affected by such law) as Parliament may deem necessary. (2) No su", "p": "I", "pn": "The Union and its Territory", "clr": "#E8A838"}, {"n": "5", "t": "Citizenship at the commencement of the Constitution", "c": "At the commencement of this Constitution, every person who has his domicile in the territory of India and— (a) who was born in the territory of India; or (b) either of whose parents was born in the territory of India; or (c) who has been ordinarily resident in the territory of India for not less than five years immediately preceding such commencement, shall be a citizen of India.", "p": "II", "pn": "Citizenship", "clr": "#4CAF82"}, {"n": "6", "t": "Rights of citizenship of certain persons who have migrated to India from", "c": "Pakistan:- Notwithstanding anything in article 5, a person who has migrated to the territory of India from the territory now included in Pakistan shall be deemed to be a citizen of India at the commencement of this Constitution if— (a) he or either of his parents or any of his grand-parents was born in India as defined in the Government of India Act, 1935 (as originally enacted); and (b) (i) in the case where such person has so migrated before the nineteenth day of July, 1948, he has been ordinarily resident in the territory of India since the ", "p": "II", "pn": "Citizenship", "clr": "#4CAF82"}, {"n": "7", "t": "Rights of citizenship of certain migrants to Pakistan", "c": "Notwithstanding anything in articles 5 and 6, a person who has after the first day of March, 1947, migrated from the territory of India to the territory now included in Pakistan shall not be deemed to be a citizen of India: Provided that nothing in this article shall apply to a person who, after having so migrated to the territory now included in Pakistan, has returned to the territory of India under a permit for resettlement or permanent return issued by or under the authority of any law and every such person shall for the purposes of clause (", "p": "II", "pn": "Citizenship", "clr": "#4CAF82"}, {"n": "8", "t": "Rights of citizenship of certain persons of Indian origin residing outside India:Notwithstanding anything in article 5, any person who or either of whose parents or any of whose", "c": "grand-parents was born in India as defined in the Government of India Act, 1935 (as originally enacted), and who is ordinarily residing in any country outside India as so defined shall be deemed to be a citizen of India if he has been registered as a citizen of India by the diplomatic or consular representative of India in the country where he is for the time being residing on an application made by him therefor to such diplomatic or consular representative, whether before or after the commencement of this Constitution, in the form and manner p", "p": "II", "pn": "Citizenship", "clr": "#4CAF82"}, {"n": "9", "t": "Persons voluntarily acquiring citizenship of a foreign State not to be citizens", "c": "No person shall be a citizen of India by virtue of article 5, or be deemed to be a citizen of India by virtue of article 6 or article 8, if he has voluntarily acquired the citizenship of any foreign State.", "p": "II", "pn": "Citizenship", "clr": "#4CAF82"}, {"n": "10", "t": "Continuance of the rights of citizenship", "c": "Every person who is or is deemed to be a citizen of India under any of the foregoing provisions of this Part shall, subject to the provisions of any law that may be made by Parliament, continue to be such citizen.", "p": "II", "pn": "Citizenship", "clr": "#4CAF82"}, {"n": "11", "t": "Parliament to regulate the right of citizenship by law", "c": "Nothing in the foregoing provisions of this Part shall derogate from the power of Parliament to make any provision with respect to the acquisition and termination of citizenship and all other matters relating to citizenship. THE CONSTITUTION OF INDIA PART-III FUNDAMENTAL RIGHTS General", "p": "II", "pn": "Citizenship", "clr": "#4CAF82"}, {"n": "12", "t": "Definition", "c": "In this Part, unless the context otherwise requires, the “State” includes the Government and Parliament of India and the Government and the Legislature of each of the States and all local or other authorities within the territory of India or under the control of the Government of India.", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "12B", "t": "Application of Acts of Parliament and of the Legislature of the State of Mizoram", "c": "to autonomous districts and autonomous regions in the State of Mizoram:Notwithstanding anything in this Constitution,— (a) no Act of the Legislature of the State of Mizoram in respect of any of the matters specified in paragraph 3 of this Schedule as matters with respect to which a District Council or a Regional Council may make laws, and no Act of the Legislature of the State of Mizoram prohibiting or restricting the consumption of any non-distilled alcoholic liquor shall apply to any autonomous district or autonomous region in that State unle", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "13", "t": "Laws inconsistent with or in derogation of the fundamental rights", "c": "(1) All laws in force in the territory of India immediately before the commencement of this Constitution, in so far as they are inconsistent with the provisions of this Part, shall, to the extent of such inconsistency, be void. (2) The State shall not make any law which takes away or abridges the rights conferred by this Part and any law made in contravention of this clause shall, to the extent of the contravention, be void. (3) In this article, unless the context otherwise requires,— (a) “law” includes any Ordinance, order, bye-law, rule, regu", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "14", "t": "Equality before law", "c": "The State shall not deny to any person equality before the law or the equal protection of the laws within the territory of India.", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "15", "t": "Prohibition of discrimination on grounds of religion, race, caste, sex or place of", "c": "birth:- (1) The State shall not discriminate against any citizen on grounds only of religion, race, caste, sex, place of birth or any of them.", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "16", "t": "Equality of opportunity in matters of public employment", "c": "(1) There shall be equality of opportunity for all citizens in matters relating to employment or appointment to any office under the State. (2) No citizen shall, on grounds only of religion, race, caste, sex, descent, place of birth, residence or any of them, be ineligible for, or discriminated against in respect of, any employment or office under the State. (3) Nothing in this article shall prevent Parliament from making any law prescribing, in regard to a class or classes of employment or appointment to an office 1[under the Government of, or", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "17", "t": "Abolition of Untouchability", "c": "“Untouchability” is abolished and its practice in any form is forbidden. The enforcement of any disability arising out of “Untouchability” shall be an offence punishable in accordance with law.", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "17B", "t": "Protection of wild animals and birds.]", "c": "", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "18", "t": "Abolition of titles", "c": "(1) No title, not being a military or academic distinction, shall be conferred by the State. (2) No citizen of India shall accept any title from any foreign State. (3) No person who is not a citizen of India shall, while he holds any office of profit or trust under the State, accept without the consent of the President any title from any foreign State.", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "19", "t": "Protection of certain rights regarding freedom of speech, etc", "c": "(1) All citizens shall have the right— (a) to freedom of speech and expression; (b) to assemble peaceably and without arms; (c) to form associations or unions 1[or co-operative societies]; (d) to move freely throughout the territory of India; (e) to reside and settle in any part of the territory of India; 2[and] (f) 3[* * * * *] (g) to practise any profession, or to carry on any occupation, trade or business. [(2) Nothing in sub-clause (a) of clause (1) shall affect the operation of any existing law, or prevent the State from making any law, in", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "20", "t": "Protection in respect of conviction for offences", "c": "(1) No person shall be convicted of any offence except for violation of a law in force at the time of the commission of the Act charged as an offence, nor be subjected to a penalty greater than that which might have been inflicted under the law in force at the time of the commission of the offence. (2) No person shall be prosecuted and punished for the same offence more than once. (3) No person accused of any offence shall be compelled to be a witness against himself.", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "20B", "t": "Autonomous regions in the Union territory of Mizoram to be autonomous districts and transitory provisions consequent thereto", "c": "(1) Notwithstanding anything in this Schedule,— (a) every autonomous region existing immediately before the prescribed date in the Union territory of Mizoram shall, on and from that date, be an autonomous district in that Union territory (hereafter referred to as the corresponding new district) and the Administrator thereof may, by one or more orders, direct that such consequential amendments as are necessary to give effect to the provisions of this clause shall be made in paragraph 20 of this Schedule (including Part III of the table appended ", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "20C", "t": "Interpretation", "c": "Subject to any provision made in this behalf, the provisions of this Schedule shall, in their application to the Union territory of Mizoram, have effect— (1) as if references to the Governor and Government of the State were references to the Administrator of the Union territory appointed under article 239, references to State (except in the expression \"Government of the State\") were references to the Union territory of Mizoram and references to the State Legislature were references to the Legislative Assembly of the Union territory of Mizoram; ", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "21", "t": "Protection of life and personal liberty", "c": "No person shall be deprived of his life or personal liberty except according to procedure established by law. [21A. Right to education:- The State shall provide free and compulsory education to all children of the age of six to fourteen years in such manner as the State may, by law, determine.]", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "22", "t": "Protection against arrest and detention in certain cases", "c": "(1) No person who is arrested shall be detained in custody without being informed, as soon as may be, of the grounds for such arrest nor shall he be denied the right to consult, and to be defended by, a legal practitioner of his choice. (2) Every person who is arrested and detained in custody shall be produced before the nearest magistrate within a period of twenty-four hours of such arrest excluding the time necessary for the journey from the place of arrest to the court of the magistrate and no such person shall be detained in custody beyond ", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "23", "t": "Prohibition of traffic in human beings and forced labour", "c": "(1) Traffic in human beings and begar and other similar forms of forced labour are prohibited and any contravention of this provision shall be an offence punishable in accordance with law. (2) Nothing in this article shall prevent the State from imposing compulsory service for public purposes, and in imposing such service the State shall not make any discrimination on grounds only of religion, race, caste or class or any of them.", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "24", "t": "Prohibition of employment of children in factories, etc", "c": "No child below the age of fourteen years shall be employed to work in any factory or mine or engaged in any other hazardous employment. Right to Freedom of Religion", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "25", "t": "Freedom of conscience and free profession, practice and propagation of religion:(1) Subject to public order, morality and health and to the other provisions of this Part, all", "c": "persons are equally entitled to freedom of conscience and the right freely to profess, practise and propagate religion. (2) Nothing in this article shall affect the operation of any existing law or prevent the State from making any law— (a) regulating or restricting any economic, financial, political or other secular activity which may be associated with religious practice; (b) providing for social welfare and reform or the throwing open of Hindu religious institutions of a public character to all classes and sections of Hindus. Explanation I:-", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "26", "t": "Freedom to manage religious affairs", "c": "Subject to public order, morality and health, every religious denomination or any section thereof shall have the right— (a) to establish and maintain institutions for religious and charitable purposes; (b) to manage its own affairs in matters of religion; (c) to own and acquire movable and immovable property; and (d) to administer such property in accordance with law.", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "27", "t": "Freedom as to payment of taxes for promotion of any particular religion", "c": "No person shall be compelled to pay any taxes, the proceeds of which are specifically appropriated in payment of expenses for the promotion or maintenance of any particular religion or religious denomination.", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "28", "t": "Freedom as to attendance at religious instruction or religious worship in certain", "c": "educational institutions:- (1) No religious instruction shall be provided in any educational institution wholly maintained out of State funds. (2) Nothing in clause (1) shall apply to an educational institution which is administered by the State but has been established under any endowment or trust which requires that religious instruction shall be imparted in such institution. (3) No person attending any educational institution recognised by the State or receiving aid out of State funds shall be required to take part in any religious instructi", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "29", "t": "Protection of interests of minorities", "c": "(1) Any section of the citizens residing in the territory of India or any part thereof having a distinct language, script or culture of its own shall have the right to conserve the same. (2) No citizen shall be denied admission into any educational institution maintained by the State or receiving aid out of State funds on grounds only of religion, race, caste, language or any of them. THE CONSTITUTION OF INDIA (Part III. — Fundamental Rights)", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "30", "t": "Right of minorities to establish and administer educational institutions", "c": "(1) All minorities, whether based on religion or language, shall have the right to establish and administer educational institutions of their choice. [(1A) In making any law providing for the compulsory acquisition of any property of an educational institution established and administered by a minority, referred to in clause (1), the State shall ensure that the amount fixed by or determined under such law for the acquisition of such property is such as would not restrict or abrogate the right guaranteed under that clause.] (2) The State shall n", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "31", "t": "Posts and telegraphs; telephones, wireless, broadcasting and other like forms of", "c": "communication.", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "31A", "t": "Saving of laws providing for acquisition of estates, etc", "c": "6[(1) Notwithstanding anything contained in article 13, no law providing for— (a) the acquisition by the State of any estate or of any rights therein or the extinguishment or modification of any such rights, or (b) the taking over of the management of any property by the State for a limited period either in the public interest or in order to secure the proper management of the property, or (c) the amalgamation of two or more corporations either in the public interest or in order to secure the proper management of any of the corporations, or", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "32", "t": "Remedies for enforcement of rights conferred by this Part", "c": "(1) The right to move the Supreme Court by appropriate proceedings for the enforcement of the rights conferred by this Part is guaranteed. (2) The Supreme Court shall have power to issue directions or orders or writs, including writs in the nature of habeas corpus, mandamus, prohibition, quo warranto and certiorari, whichever may be appropriate, for the enforcement of any of the rights conferred by this Part. (3) Without prejudice to the powers conferred on the Supreme Court by clauses (1) and (2), Parliament may by law empower any other court ", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "33", "t": "Theatres and dramatic performances; cinemas subject to the provisions of entry 60 of", "c": "List I; sports, entertainments and amusements.", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "34", "t": "Restriction on rights conferred by this Part while martial law is in force in any", "c": "area:- Notwithstanding anything in the foregoing provisions of this Part, Parliament may by law indemnify any person in the service of the Union or of a State or any other person in respect of any act done by him in connection with the maintenance or restoration of order in any area within the territory of India where martial law was in force or validate any sentence passed, punishment inflicted, forfeiture ordered or other act done under martial law in such area.", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "35", "t": "Legislation to give effect to the provisions of this Part", "c": "Notwithstanding anything in this Constitution,— (a) Parliament shall have, and the Legislature of a State shall not have, power to make laws— (i) with respect to any of the matters which under clause (3) of article 16, clause (3) of article 32, article 33 and article 34 may be provided for by law made by Parliament; and (ii) for prescribing punishment for those acts which are declared to be offences under this Part, and Parliament shall, as soon as may be after the commencement of this Constitution, make laws for prescribing punishment for the ", "p": "III", "pn": "Fundamental Rights", "clr": "#E05252"}, {"n": "36", "t": "Definition", "c": "In this Part, unless the context otherwise requires, —the State” has the same meaning as in Part III.", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "37", "t": "Application of the principles contained in this Part", "c": "The provisions contained in this Part shall not be enforceable by any court, but the principles therein laid down are nevertheless fundamental in the governance of the country and it shall be the duty of the State to apply these principles in making laws.", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "38", "t": "State to secure a social order for the promotion of welfare of the people:1", "c": "[(1)] The State shall strive to promote the welfare of the people by securing and protecting as effectively as it may a social order in which justice, social, economic and political, shall inform all the institutions of the national life. [(2) The State shall, in particular, strive to minimise the inequalities in income, and endeavour to eliminate inequalities in status, facilities and opportunities, not only amongst individuals but also amongst groups of people residing in different areas or engaged in different vocations.]", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "39", "t": "Certain principles of policy to be followed by the State", "c": "The State shall, in particular, direct its policy towards securing— (a) that the citizens, men and women equally, have the right to an adequate means of livelihood; (b) that the ownership and control of the material resources of the community are so distributed as best to subserve the common good; (c) that the operation of the economic system does not result in the concentration of wealth and means of production to the common detriment; (d) that there is equal pay for equal work for both men and women; (e) that the health and strength of worker", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "40", "t": "Organisation of village panchayats", "c": "The State shall take steps to organise village panchayats and endow them with such powers and authority as may be necessary to enable them to function as units of self-government.", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "41", "t": "Right to work, to education and to public assistance in certain cases", "c": "The State shall, within the limits of its economic capacity and development, make effective provision for securing the right to work, to education and to public assistance in cases of unemployment, old age, sickness and disablement, and in other cases of undeserved want.", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "42", "t": "Provision for just and humane conditions of work and maternity relief", "c": "The State shall make provision for securing just and humane conditions of work and for maternity relief.", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "43", "t": "Living wage, etc., for workers", "c": "The State shall endeavour to secure, by suitable legislation or economic organisation or in any other way, to all workers, agricultural, industrial or otherwise, work, a living wage, conditions of work ensuring a decent standard of life and full enjoyment of leisure and social and cultural opportunities and, in particular, the State shall endeavour to promote cottage industries on an individual or co-operative basis in rural areas.", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "44", "t": "Uniform civil code for the citizens", "c": "The State shall endeavour to secure for the citizens a uniform civil code throughout the territory of India. [45. Provision for early childhood care and education to children below the age of six years:- The State shall endeavour to provide early childhood care and education for all children until they complete the age of six years.]", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "45", "t": "Banking", "c": "", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "46", "t": "Promotion of educational and economic interests of Scheduled Castes, Scheduled", "c": "Tribes and other weaker sections:- The State shall promote with special care the educational and economic interests of the weaker sections of the people, and, in particular, of the Scheduled Castes and the Scheduled Tribes, and shall protect them from social injustice and all forms of exploitation.", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "47", "t": "Duty of the State to raise the level of nutrition and the standard of living and to", "c": "improve public health:- The State shall regard the raising of the level of nutrition and the standard of living of its people and the improvement of public health as among its primary duties and, in particular, the State shall endeavour to bring about prohibition of the consumption except for medicinal purposes of intoxicating drinks and of drugs which are injurious to health.", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "48", "t": "Organisation of agriculture and animal husbandry", "c": "The State shall endeavour to organise agriculture and animal husbandry on modern and scientific lines and shall, in particular, take steps for preserving and improving the breeds, and prohibiting the slaughter, of cows and calves and other milch and draught cattle.", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "49", "t": "Protection of monuments and places and objects of national importance", "c": "It shall be the obligation of the State to protect every monument or place or object of artistic or historic interest, 2[declared by or under law made by Parliament] to be of national importance, from spoliation, disfigurement, destruction, removal, disposal or export, as the case may be.", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "50", "t": "Separation of judiciary from executive", "c": "The State shall take steps to separate the judiciary from the executive in the public services of the State.", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "51", "t": "Promotion of international peace and security.—The State shall endeavour to —", "c": "(a) promote international peace and security; (b) maintain just and honourable relations between nations; (c) foster respect for international law and treaty obligations in the dealings of organised peoples with one another; and (d) encourage settlement of international disputes by arbitration.", "p": "IV", "pn": "Directive Principles", "clr": "#9B6DFF"}, {"n": "51A", "t": "Fundamental duties", "c": "It shall be the duty of every citizen of India— (a) to abide by the Constitution and respect its ideals and institutions, the National Flag and the National Anthem; (b) to cherish and follow the noble ideals which inspired our national struggle for freedom; (c) to uphold and protect the sovereignty, unity and integrity of India; (d) to defend the country and render national service when called upon to do so; (e) to promote harmony and the spirit of common brotherhood amongst all the people of India transcending religious, linguistic and regiona", "p": "IVA", "pn": "Fundamental Duties", "clr": "#FF7043"}, {"n": "52", "t": "The President of India", "c": "There shall be a President of India.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "53", "t": "Executive power of the Union", "c": "(1) The executive power of the Union shall be vested in the President and shall be exercised by him either directly or through officers subordinate to him in accordance with this Constitution. (2) Without prejudice to the generality of the foregoing provision, the supreme command of the Defence Forces of the Union shall be vested in the President and the exercise thereof shall be regulated by law. (3) Nothing in this article shall— (a) be deemed to transfer to the President any functions conferred by any existing law on the Government of any St", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "54", "t": "Election of President", "c": "The President shall be elected by the members of an electoral college consisting of— (a) the elected members of both Houses of Parliament; and (b) the elected members of the Legislative Assemblies of the States. [Explanation:- In this article and in article 55, “State” includes the National Capital Territory of Delhi and the Union territory of Pondicherry.]", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "55", "t": "Manner of election of President", "c": "(1) As far as practicable, there shall be uniformity in the scale of representation of the different States at the election of the President. (2) For the purpose of securing such uniformity among the States inter se as well as parity between the States as a whole and the Union, the number of votes which each elected member of Parliament and of the Legislative Assembly of each State is entitled to cast at such election shall be determined in the following manner:—", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "56", "t": "Term of office of President", "c": "(1) The President shall hold office for a term of five years from the date on which he enters upon his office: Provided that— (a) the President may, by writing under his hand addressed to the Vice-President, resign his office; (b) the President may, for violation of the Constitution, be removed from office by impeachment in the manner provided in article 61; (c) the President shall, notwithstanding the expiration of his term, continue to hold office until his successor enters upon his office.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "57", "t": "Eligibility for re-election", "c": "A person who holds, or who has held, office as President shall, subject to the other provisions of this Constitution, be eligible for re-election to that office.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "58", "t": "Qualifications for election as President", "c": "(1) No person shall be eligible for election as President unless he— (a) is a citizen of India, (b) has completed the age of thirty-five years, and (c) is qualified for election as a member of the House of the People. (2) A person shall not be eligible for election as President if he holds any office of profit under the Government of India or the Government of any State or under any local or other authority subject to the control of any of the said Governments. Explanation:- For the purposes of this article, a person shall not be deemed to hold", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "59", "t": "Conditions of President's office", "c": "(1) The President shall not be a member of either House of Parliament or of a House of the Legislature of any State, and if a member of either House of Parliament or of a House of the Legislature of any State be elected President, he shall be deemed to have vacated his seat in that House on the date on which he enters upon his office as President. (2) The President shall not hold any other office of profit. (3) The President shall be entitled without payment of rent to the use of his official residences and shall be also entitled to such emolum", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "60", "t": "Oath or affirmation by the President", "c": "Every President and every person acting as President or discharging the functions of the President shall, before entering upon his office, make and subscribe in the presence of the Chief Justice of India or, in his absence, the senior-most Judge of the Supreme Court available, an oath or affirmation in the following form, that is to say— “I, A.B., do swear in the name of God that I will faithfully execute the office solemnly affirm of President (or discharge the functions of the President) of India and will to the best of my ability preserve, p", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "61", "t": "Procedure for impeachment of the President", "c": "(1) When a President is to be impeached for violation of the Constitution, the charge shall be preferred by either House of Parliament. (2) No such charge shall be preferred unless— (a) the proposal to prefer such charge is contained in a resolution which has been moved after at least fourteen days' notice in writing signed by not less than one-fourth of the total number of members of the House has been given of their intention to move the resolution, and (b) such resolution has been passed by a majority of not less than two-thirds of the total", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "62", "t": "Time of holding election to fill vacancy in the office of President and the term of", "c": "office of person elected to fill casual vacancy:- (1) An election to fill a vacancy caused by the expiration of the term of office of President shall be completed before the expiration of the term. THE CONSTITUTION OF INDIA (Part V. — The Union) (2) An election to fill a vacancy in the office of President occurring by reason of his death, resignation or removal, or otherwise shall be held as soon as possible after, and in no case later than six months from, the date of occurrence of the vacancy; and the person elected to fill the vacancy shall,", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "63", "t": "The Vice-President of India", "c": "There shall be a Vice-President of India.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "64", "t": "The Vice-President to be ex officio Chairman of the Council of States.—The VicePresident shall be ex officio Chairman of the Council of the States and shall not hold any", "c": "other office of profit: Provided that during any period when the Vice-President acts as President or discharges the functions of the President under article 65, he shall not perform the duties of the office of Chairman of the Council of States and shall not be entitled to any salary or allowance payable to the Chairman of the Council of States under article 97.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "65", "t": "The Vice-President to act as President or to discharge his functions during casual", "c": "vacancies in the office, or during the absence, of President:- (1) In the event of the occurrence of any vacancy in the office of the President by reason of his death, resignation or removal, or otherwise, the Vice-President shall act as President until the date on which a new President elected in accordance with the provisions of this Chapter to fill such vacancy enters upon his office. (2) When the President is unable to discharge his functions owing to absence, illness or any other cause, the Vice-President shall discharge his functions unti", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "66", "t": "Election of Vice-President", "c": "(1) The Vice-President shall be elected by the 1[members of an electoral college consisting of the members of both Houses of Parliament] in accordance with the system of proportional representation by means of the single transferable vote and the voting at such election shall be by secret ballot. (2) The Vice-President shall not be a member of either House of Parliament or of a House of the Legislature of any State, and if a member of either House of Parliament or of a House of the Legislature of any State be elected Vice-President, he shall be", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "67", "t": "Term of office of Vice-President", "c": "The Vice-President shall hold office for a term of five years from the date on which he enters upon his office: Provided that— (a) a Vice-President may, by writing under his hand addressed to the President, resign his office; (b) a Vice-President may be removed from his office by a resolution of the Council of States passed by a majority of all the then members of the Council and agreed to by the House of the People; but no resolution for the purpose of this clause shall be moved unless at least fourteen days' notice has been given of the inten", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "68", "t": "The Survey of India, the Geological, Botanical, Zoological and Anthropological", "c": "Surveys of India; Meteorological organisations.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "69", "t": "Oath or affirmation by the Vice-President", "c": "Every Vice-President shall, before entering upon his office, make and subscribe before the President, or some person appointed in that behalf by him, an oath or affirmation in the following form, that is to say— “I, A.B., do swear in the name of God that I will bear true faith and solemnly affirm allegiance to the Constitution of India as by law established and that I will faithfully discharge the duty upon which I am about to enter.”.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "70", "t": "Discharge of President's functions in other contingencies", "c": "Parliament may make such provisions as it thinks fit for the discharge of the functions of the President in any contingency not provided for in this Chapter. [71. Matters relating to, or connected with, the election of a President or VicePresident:- (1) All doubts and disputes arising out of or in connection with the election of a President or Vice-President shall be inquired into and decided by the Supreme Court whose decision shall be final. (2) If the election of a person as President or Vice-President is declared void by the Supreme Court, ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "71", "t": "Union pensions, that is to say, pensions payable by the Government of India or out of", "c": "the Consolidated Fund of India.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "72", "t": "Power of President to grant pardons, etc., and to suspend, remit or commute", "c": "sentences in certain cases:- (1) The President shall have the power to grant pardons, reprieves, respites or remissions of punishment or to suspend, remit or commute the sentence of any person convicted of any offence— (a) in all cases where the punishment or sentence is by a Court Martial; (b) in all cases where the punishment or sentence is for an offence against any law relating to a matter to which the executive power of the Union extends; (c) in all cases where the sentence is a sentence of death. (2) Nothing in sub-clause (a) of clause (1", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "73", "t": "Extent of executive power of the Union", "c": "(1) Subject to the provisions of this Constitution, the executive power of the Union shall extend— (a) to the matters with respect to which Parliament has power to make laws; and (b) to the exercise of such rights, authority and jurisdiction as are exercisable by the Government of India by virtue of any treaty or agreement:", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "74", "t": "Council of Ministers to aid and advise President", "c": "2[(1) There shall be a Council of Ministers with the Prime Minister at the head to aid and advise the President who shall, in the exercise of his functions, act in accordance with such advice:] [Provided that the President may require the Council of Ministers to reconsider such advice, either generally or otherwise, and the President shall act in accordance with the advice tendered after such reconsideration.] (2) The question whether any, and if so what, advice was tendered by Ministers to the President shall not be inquired into in any court.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "75", "t": "Other provisions as to Ministers", "c": "(1) The Prime Minister shall be appointed by the President and the other Ministers shall be appointed by the President on the advice of the Prime Minister. [(1A) The total number of Ministers, including the Prime Minister, in the Council of Ministers shall not exceed fifteen per cent. of the total number of members of the House of the People.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "76", "t": "Attorney-General for India", "c": "(1) The President shall appoint a person who is qualified to be appointed a Judge of the Supreme Court to be Attorney-General for India. (2) It shall be the duty of the Attorney-General to give advice to the Government of India upon such legal matters, and to perform such other duties of a legal character, as may from time to time be referred or assigned to him by the President, and to discharge the functions conferred on him by or under this Constitution or any other law for the time being in force. (3) In the performance of his duties the Att", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "77", "t": "Conduct of business of the Government of India", "c": "(1) All executive action of the Government of India shall be expressed to be taken in the name of the President. (2) Orders and other instruments made and executed in the name of the President shall be authenticated in such manner as may be specified in rules1 to be made by the President, and the validity of an order or instrument which is so authenticated shall not be called in question on the ground that it is not an order or instrument made or executed by the President. (3) The President shall make rules for the more convenient transaction o", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "78", "t": "Duties of Prime Minister as respects the furnishing of information to the", "c": "President, etc.:- It shall be the duty of the Prime Minister— (a) to communicate to the President all decisions of the Council of Ministers relating to the administration of the affairs of the Union and proposals for legislation; (b) to furnish such information relating to the administration of the affairs of the Union and proposals for legislation as the President may call for; and (c) if the President so requires, to submit for the consideration of the Council of Ministers any matter on which a decision has been taken by a Minister but which ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "79", "t": "Constitution of Parliament", "c": "There shall be a Parliament for the Union which shall consist of the President and two Houses to be known respectively as the Council of States and the House of the People.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "80", "t": "Composition of the Council of States", "c": "(1) 1[2*** The Council of States] shall consist of— (a) twelve members to be nominated by the President in accordance with the provisions of clause (3); and (b) not more than two hundred and thirty-eight representatives of the States 3[and of the Union territories.] (2) The allocation of seats in the Council of States to be filled by representatives of the States 3[and of the Union territories] shall be in accordance with the provisions in that behalf contained in the Fourth Schedule. (3) The members to be nominated by the President under sub-c", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "81", "t": "Inter-State migration; inter-State quarantine", "c": "", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "82", "t": "Readjustment after each census", "c": "Upon the completion of each census, the allocation of seats in the House of the People to the States and the division of each State into territorial constituencies shall be readjusted by such authority and in such manner as Parliament may by law determine: Provided that such readjustment shall not affect representation in the House of the People until the dissolution of the then existing House: Provided further that such readjustment shall take effect from such date as the President may, by order, specify and until such readjustment takes effec", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "83", "t": "Duration of Houses of Parliament", "c": "(1) The Council of States shall not be subject to dissolution, but as nearly as possible one-third of the members thereof shall retire as soon as may be on the expiration of every second year in accordance with the provisions made in that behalf by Parliament by law. (2) The House of the People, unless sooner dissolved, shall continue for 2[five years] from the date appointed for its first meeting and no longer and the expiration of the said period of 2[five years] shall operate as a dissolution of the House: Provided that the said period may, ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "84", "t": "Qualification for membership of Parliament", "c": "A person shall not be qualified to be chosen to fill a seat in Parliament unless he— [(a) is a citizen of India, and makes and subscribes before some person authorised in that behalf by the Election Commission an oath or affirmation according to the form set out for the purpose in the Third Schedule;] (b) is, in the case of a seat in the Council of States, not less than thirty years of age and, in the case of a seat in the House of the People, not less than twenty-five years of age; and (c) possesses such other qualifications as may be prescrib", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "85", "t": "Corporation tax", "c": "", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "86", "t": "Right of President to address and send messages to Houses", "c": "(1) The President may address either House of Parliament or both Houses assembled together, and for that purpose require the attendance of members. (2) The President may send messages to either House of Parliament, whether with respect to a Bill then pending in Parliament or otherwise, and a House to which any message is so sent shall with all convenient despatch consider any matter required by the message to be taken into consideration.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "87", "t": "Special address by the President", "c": "(1) At the commencement of 2[the first session after each general election to the House of the People and at the commencement of the first session of each year] the President shall address both Houses of Parliament assembled together and inform Parliament of the causes of its summons. (2) Provision shall be made by the rules regulating the procedure of either House for the allotment of time for discussion of the matters referred to in such address 3[***].", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "88", "t": "Rights of Ministers and Attorney-General as respects Houses", "c": "Every Minister and the Attorney-General of India shall have the right to speak in, and otherwise to take part in the proceedings of, either House, any joint sitting of the Houses, and any committee of Parliament of which he may be named a member, but shall not by virtue of this article be entitled to vote.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "89", "t": "The Chairman and Deputy Chairman of the Council of States", "c": "(1) The VicePresident of India shall be ex officio Chairman of the Council of States. (2) The Council of States shall, as soon as may be, choose a member of the Council to be Deputy Chairman thereof and, so often as the office of Deputy Chairman becomes vacant, the Council shall choose another member to be Deputy Chairman thereof.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "90", "t": "Vacation and resignation of, and removal from, the office of Deputy Chairman:A member holding office as Deputy Chairman of the Council of States—", "c": "(a) shall vacate his office if he ceases to be a member of the Council; (b) may at any time, by writing under his hand addressed to the Chairman, resign his office; and (c) may be removed from his office by a resolution of the Council passed by a majority of all the then members of the Council: Provided that no resolution for the purpose of clause (c) shall be moved unless at least fourteen days‘ notice has been given of the intention to move the resolution.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "91", "t": "Power of the Deputy Chairman or other person to perform the duties of the office", "c": "of, or to act as, Chairman:- (1) While the office of Chairman is vacant, or during any period when theVice-President is acting as, or discharging the functions of, President, the duties of the office shall be performed by the Deputy Chairman, or, if the office of Deputy Chairman is also vacant, by such member of the Council of States as the President may appoint for the purpose. (2) During the absence of the Chairman from any sitting of the Council of States the Deputy Chairman, or, if he is also absent, such person as may be determined by the ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "92", "t": "The Chairman or the Deputy Chairman not to preside while a resolution for his", "c": "removal from office is under consideration:- (1) At any sitting of the Council of States, while any resolution for the removal of the Vice-President from his office is under consideration, the Chairman, or while any resolution for the removal of the Deputy Chairman from his office is under consideration, the Deputy Chairman, shall not, though he is present, preside, and the provisions of clause (2) of article 91 shall apply in relation to every such sitting as they apply in relation to a sitting from which the Chairman, or, as the case may be, ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "93", "t": "The Speaker and Deputy Speaker of the House of the People", "c": "The House of the People shall, as soon as may be, choose two members of the House to be respectively Speaker and Deputy Speaker thereof and, so often as the office of Speaker or Deputy Speaker becomes vacant, the House shall choose another member to be Speaker or Deputy Speaker, as the case may be.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "94", "t": "Vacation and resignation of, and removal from, the offices of Speaker and Deputy", "c": "Speaker:- A member holding office as Speaker or Deputy Speaker of the House of the People— (a) shall vacate his office if he ceases to be a member of the House of the People; (b) may at any time, by writing under his hand addressed, if such member is the Speaker, to the Deputy Speaker, and if such member is the Deputy Speaker, to the Speaker, resign his office; and (c) may be removed from his office by a resolution of the House of the People passed by a majority of all the then members of the House: Provided that no resolution for the purpose o", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "95", "t": "Power of the Deputy Speaker or other person to perform the duties of the office", "c": "of, or to act as, Speaker:- (1) While the office of Speaker is vacant, the duties of the office shall be performed by the Deputy Speaker or, if the office of Deputy Speaker is also vacant, by such member of the House of the People as the President may appoint for the purpose. (2) During the absence of the Speaker from any sitting of the House of the People the Deputy Speaker or, if he is also absent, such person as may be determined by the rules of procedure of the House, or, if no such person is present, such other person as may be determined ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "96", "t": "The Speaker or the Deputy Speaker not to preside while a resolution for his", "c": "removal from office is under consideration:- (1) At any sitting of the House of the People, while any resolution for the removal of the Speaker from his office is under consideration, the Speaker, or while any resolution for the removal of the Deputy Speaker from his office is under consideration, the Deputy Speaker, shall not, though he is present, preside, and the provisions of clause (2) of article 95 shall apply in relation to every such sitting as they apply in relation to a sitting from which the Speaker, or, as the case may be, the Deput", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "97", "t": "Salaries and allowances of the Chairman and Deputy Chairman and the Speaker", "c": "and Deputy Speaker:- There shall be paid to the Chairman and the Deputy Chairman of the Council of States, and to the Speaker and the Deputy Speaker of the House of the People, such salaries and allowances as may be respectively fixed by Parliament by law and, until provision in that behalf is so made, such salaries and allowances as are specified in the Second Schedule.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "98", "t": "Secretariat of Parliament", "c": "(1) Each House of Parliament shall have a separate secretarial staff: Provided that nothing in this clause shall be construed as preventing the creation of posts common to both Houses of Parliament. (2) Parliament may by law regulate the recruitment, and the conditions of service of persons appointed, to the secretarial staff of either House of Parliament. (3) Until provision is made by Parliament under clause (2), the President may, after consultation with the Speaker of the House of the People or the Chairman of the Council of States, as the ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "99", "t": "Oath or affirmation by members", "c": "Every member of either House of Parliament shall, before taking his seat, make and subscribe before the President, or some person appointed in that behalf by him, an oath or affirmation according to the form set out for the purpose in the Third Schedule.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "100", "t": "Voting in Houses, power of Houses to act notwithstanding vacancies and", "c": "quorum:- (1) Save as otherwise provided in this Constitution, all questions at any sitting of either House or joint sitting of the Houses shall be determined by a majority of votes of the members present and voting, other than the Speaker or person acting as Chairman or Speaker. The Chairman or Speaker, or person acting as such, shall not vote in the first instance, but shall have and exercise a casting vote in the case of an equality of votes. (2) Either House of Parliament shall have power to act notwithstanding any vacancy in the membership ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "101", "t": "Vacation of seats", "c": "(1) No person shall be a member of both Houses of Parliament and provision shall be made by Parliament by law for the vacation by a person who is chosen a member of both Houses of his seat in one House or the other.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "102", "t": "Disqualifications for membership", "c": "(1) A person shall be disqualified for being chosen as, and for being, a member of either House of Parliament— [(a) if he holds any office of profit under the Government of India or the Government of any State, other than an office declared by Parliament by law not to disqualify its holder;] (b) if he is of unsound mind and stands so declared by a competent court; (c) if he is an undischarged insolvent; (d) if he is not a citizen of India, or has voluntarily acquired the citizenship of a foreign State, or is under any acknowledgment of allegian", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "103", "t": "The Additional Emoluments (Compulsory Deposit) Act, 1974 (Central Act 37", "c": "of 1974).", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "104", "t": "Penalty for sitting and voting before making oath or affirmation under article 99", "c": "or when not qualified or when disqualified:- If a person sits or votes as a member of either House of Parliament before he has complied with the requirements of article 99, or when he knows that he is not qualified or that he is disqualified for membership thereof, or that he is prohibited from so doing by the provisions of any law made by Parliament, he shall be liable in respect of each day on which he so sits or votes to a penalty of five hundred rupees to be recovered as a debt due to the Union. Powers, Privileges and Immunities of Parliame", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "105", "t": "Powers, privileges, etc., of the Houses of Parliament and of the members and", "c": "committees thereof:- (1) Subject to the provisions of this Constitution and to the rules and standing orders regulating the procedure of Parliament, there shall be freedom of speech in Parliament. (2) No Member of Parliament shall be liable to any proceedings in any court in respect of anything said or any vote given by him in Parliament or any committee thereof, and no person shall be so liable in respect of the publication by or under the authority of either House of Parliament of any report, paper, votes or proceedings. [(3) In other respect", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "106", "t": "Salaries and allowances of members", "c": "Members of either House of Parliament shall be entitled to receive such salaries and allowances as may from time to time be determined by Parliament by law and, until provision in that respect is so made, allowances at such rates and upon such conditions as were immediately before the commencement of this Constitution applicable in the case of members of the Constituent Assembly of the Dominion of India. Legislative Procedure", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "107", "t": "Provisions as to introduction and passing of Bills", "c": "(1) Subject to the provisions of articles 109 and 117 with respect to Money Bills and other financial Bills, a Bill may originate in either House of Parliament. (2) Subject to the provisions of articles 108 and 109, a Bill shall not be deemed to have been passed by the Houses of Parliament unless it has been agreed to by both Houses, either without amendment or with such amendments only as are agreed to by both Houses. (3) A Bill pending in Parliament shall not lapse by reason of the prorogation of the Houses. (4) A Bill pending in the Council ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "108", "t": "Joint sitting of both Houses in certain cases", "c": "(1) If after a Bill has been passed by one House and transmitted to the other House— (a) the Bill is rejected by the other House; or (b) the Houses have finally disagreed as to the amendments to be made in the Bill; or (c) more than six months elapse from the date of the reception of the Bill by the other House without the Bill being passed by it, the President may, unless the Bill has elapsed by reason of a dissolution of the House of the People, notify to the Houses by message if they are sitting or by public notification if they are not sitt", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "109", "t": "Special procedure in respect of Money Bills", "c": "(1) A Money Bill shall not be introduced in the Council of States. (2) After a Money Bill has been passed by the House of the People it shall be transmitted to the Council of States for its recommendations and the Council of States shall within a period of fourteen days from the date of its receipt of the Bill return the Bill to the House of the People with its recommendations and the House of the People may thereupon either accept or reject all or any of the recommendations of the Council of States. (3) If the House of the People accepts any o", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "110", "t": "Definition of “Money Bills”", "c": "(1) For the purposes of this Chapter, a Bill shall be deemed to be a Money Bill if it contains only provisions dealing with all or any of the following matters, namely:— (a) the imposition, abolition, remission, alteration or regulation of any tax; (b) the regulation of the borrowing of money or the giving of any guarantee by the Government of India, or the amendment of the law with respect to any financial obligations undertaken or to be undertaken by the Government of India; (c) the custody of the Consolidated Fund or the Contingency Fund of ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "111", "t": "Assent to Bills", "c": "When a Bill has been passed by the Houses of Parliament, it shall be presented to the President, and the President shall declare either that he assents to the Bill, or that he withholds assent therefrom: Provided that the President may, as soon as possible after the presentation to him of a Bill for assent, return the Bill if it is not a Money Bill to the Houses with a message requesting that they will reconsider the Bill or any specified provisions thereof and, in particular, will consider the desirability of introducing any such amendments as", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "112", "t": "Annual financial statement", "c": "(1) The President shall in respect of every financial year cause to be laid before both the Houses of Parliament a statement of the estimated receipts and expenditure of the Government of India for that year, in this Part referred to as the annual financial statement”. THE CONSTITUTION OF INDIA (Part V. — The Union) (2) The estimates of expenditure embodied in the annual financial statement shall show separately— (a) the sums required to meet expenditure described by this Constitution as expenditure charged upon the Consolidated Fund of India; ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "113", "t": "Procedure in Parliament with respect to estimates", "c": "(1) So much of the estimates as relates to expenditure charged upon the Consolidated Fund of India shall not be submitted to the vote of Parliament, but nothing in this clause shall be construed as preventing the discussion in either House of Parliament of any of those estimates. (2) So much of the said estimates as relates to other expenditure shall be submitted in the form of demands for grants to the House of the People, and the House of the People shall have power to assent, or to refuse to assent, to any demand, or to assent to any demand ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "114", "t": "Appropriation Bills", "c": "(1) As soon as may be after the grants under article 113 have been made by the House of the People, there shall be introduced a Bill to provide for the appropriation out of the Consolidated Fund of India of all moneys required to meet— (a) the grants so made by the House of the People; and (b) the expenditure charged on the Consolidated Fund of India but not exceeding in any case the amount shown in the statement previously laid before Parliament. (2) No amendment shall be proposed to any such Bill in either House of Parliament which will have ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "115", "t": "Supplementary, additional or excess grants", "c": "(1) The President shall— (a) if the amount authorised by any law made in accordance with the provisions of article 114 to be expended for a particular service for the current financial year is found to be insufficient for the purposes of that year or when a need has arisen during the current financial year for supplementary or additional expenditure upon some new service not contemplated in the annual financial statement for that year, or THE CONSTITUTION OF INDIA (Part V. — The Union) (b) if any money has been spent on any service during a fin", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "116", "t": "Votes on account, votes of credit and exceptional grants", "c": "(1) Notwithstanding anything in the foregoing provisions of this Chapter, the House of the People shall have power— (a) to make any grant in advance in respect of the estimated expenditure for a part of any financial year pending the completion of the procedure prescribed in article 113 for the voting of such grant and the passing of the law in accordance with the provisions of article 114 in relation to that expenditure; (b) to make a grant for meeting an unexpected demand upon the resources of India when on account of the magnitude or the ind", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "117", "t": "Special provisions as to financial Bills", "c": "(1) A Bill or amendment making provision for any of the matters specified in sub-clauses (a) to (f) of clause (1) of article 110 shall not be introduced or moved except on the recommendation of the President and a Bill making such provision shall not be introduced in the Council of States: Provided that no recommendation shall be required under this clause for the moving of an amendment making provision for the reduction or abolition of any tax. (2) A Bill or amendment shall not be deemed to make provision for any of the matters aforesaid by re", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "118", "t": "Rules of procedure", "c": "(1) Each House of Parliament may make rules for regulating, subject to the provisions of this Constitution, its procedure 1[***] and the conduct of its business.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "119", "t": "Regulation by law of procedure in Parliament in relation to financial business.—", "c": "Parliament may, for the purpose of the timely completion of financial business, regulate by law the procedure of, and the conduct of business in, each House of Parliament in relation to any financial matter or to any Bill for the appropriation of moneys out of the Consolidated Fund of India, and, if and so far as any provision of any law so made is inconsistent with any rule made by a House of Parliament under clause (1) of article 118 or with any rule or standing order having effect in relation to Parliament under clause (2) of that article, s", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "120", "t": "Language to be used in Parliament", "c": "(1) Notwithstanding anything in Part XVII, but subject to the provisions of article 348, business in Parliament shall be transacted in Hindi or in English: Provided that the Chairman of the Council of States or Speaker of the House of the People, or person acting as such, as the case may be, may permit any member who cannot adequately express himself in Hindi or in English to address the House in his mother-tongue. (2) Unless Parliament by law otherwise provides, this article shall, after the expiration of a period of fifteen years from the com", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "121", "t": "Restriction on discussion in Parliament", "c": "No discussion shall take place in Parliament with respect to the conduct of any Judge of the Supreme Court or of a High Court in the discharge of his duties except upon a motion for presenting an address to the President praying for the removal of the Judge as hereinafter provided.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "122", "t": "Courts not to inquire into proceedings of Parliament", "c": "(1) The validity of any proceedings in Parliament shall not be called in question on the ground of any alleged irregularity of procedure. (2) No officer or member of Parliament in whom powers are vested by or under this Constitution for regulating procedure or the conduct of business, or for maintaining order, in Parliament shall be subject to the jurisdiction of any court in respect of the exercise by him of those powers. CHAPTER - III LEGISLATIVE POWERS OF THE PRESIDENT", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "123", "t": "Power of President to promulgate Ordinances during recess of Parliament", "c": "(1) If at any time, except when both Houses of Parliament are in session, the President is satisfied that circumstances exist which render it necessary for him to take immediate action, he may promulgate such Ordinances as the circumstances appear to him to require. (2) An Ordinance promulgated under this article shall have the same force and effect as an Act of Parliament, but every such Ordinance— (a) shall be laid before both Houses of Parliament and shall cease to operate at the expiration of six weeks from the reassembly of Parliament, or,", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "124", "t": "Establishment and constitution of Supreme Court", "c": "(1) There shall be a Supreme Court of India consisting of a Chief Justice of India and, until Parliament by law prescribes a larger number, of not more than seven2 other Judges. (2) Every Judge of the Supreme Court shall be appointed by the President by warrant under his hand and seal 3[on the recommendation of the National Judicial Appointments Commission referred to in article 124A] and shall hold office until he attains the age of sixty-five years: [* [Provided that]— * * *]", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "124B", "t": "Functions of Commission", "c": "It shall be the duty of the National Judicial Appointments Commission to— (a) recommend persons for appointment as Chief Justice of India, Judges of the Supreme Court, Chief Justices of High Courts and other Judges of High Courts; (b) recommend transfer of Chief Justices and other Judges of High Courts from one High Court to any other High 3Court; and (c) ensure that the person recommended is of ability and integrity.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "124C", "t": "Power of Parliament to make law", "c": "Parliament may, by law, regulate the procedure for the appointment of Chief Justice of India and other Judges of the Supreme Court and Chief Justices and other Judges of High Courts and empower the Commission to lay down by regulations the procedure for the discharge of its functions, the manner of selection of persons for appointment and such other matters as may be considered necessary by it.]", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "125", "t": "Salaries, etc., of Judges", "c": "1[(1) There shall be paid to the Judges of the Supreme Court such salaries as may be determined by Parliament by law and, until provision in that behalf is so made, such salaries as are specified in the Second Schedule.] (2) Every Judge shall be entitled to such privileges and allowances and to such rights in respect of leave of absence and pension as may from time to time be determined by or under law made by Parliament and, until so determined, to such privileges, allowances and rights as are specified in the Second Schedule: Provided that ne", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "126", "t": "Appointment of acting Chief Justice", "c": "When the office of Chief Justice of India is vacant or when the Chief Justice is, by reason of absence or otherwise, unable to perform the duties of his office, the duties of the office shall be performed by such one of the other Judges of the Court as the President may appoint for the purpose.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "127", "t": "Appointment of ad hoc Judges", "c": "(1) If at any time there should not be a quorum of the Judges of the Supreme Court available to hold or continue any session of the Court, 1[the National Judicial Appointments Commission on a reference made to it by the Chief Justice of India, may with the previous consent of the President] and after consultation with the Chief Justice of the High Court concerned, request in writing the attendance at the sittings of the Court, as an ad hoc Judge, for such period as may be necessary, of a Judge of a High Court duly qualified for appointment as a", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "128", "t": "Attendance of retired Judges at sittings of the Supreme Court", "c": "Notwithstanding anything in this Chapter, 2[the National Judicial Appointments Commission] may at any time, with the previous consent of the President, request any person who has held the office of a Judge of the Supreme Court or of the Federal Court 3[or who has held the office of a Judge of a High Court and is duly qualified for appointment as a Judge of the Supreme Court] to sit and act as a Judge of the Supreme Court, and every such person so requested shall, while so sitting and acting, be entitled to such allowances as the President may b", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "129", "t": "Supreme Court to be a court of record", "c": "The Supreme Court shall be a court of record and shall have all the powers of such a court including the power to punish for contempt of itself.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "130", "t": "Seat of Supreme Court", "c": "The Supreme Court shall sit in Delhi or in such other place or places, as the Chief Justice of India may, with the approval of the President, from time to time, appoint.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "131", "t": "Original jurisdiction of the Supreme Court", "c": "Subject to the provisions of this Constitution, the Supreme Court shall, to the exclusion of any other court, have original jurisdiction in any dispute— (a) between the Government of India and one or more States; or (b) between the Government of India and any State or States on one side and one or more other States on the other; or (c) between two or more States, if and in so far as the dispute involves any question (whether of law or fact) on which the existence or extent of a legal right depends: [Provided that the said jurisdiction shall not", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "132", "t": "Appellate jurisdiction of Supreme Court in appeals from High Courts in certain", "c": "cases:(1) An appeal shall lie to the Supreme Court from any judgment, decree or final order of a High Court in the territory of India, whether in a civil, criminal or other proceeding, 1[if the High Court certifies under article 134A] that the case involves a substantial question of law as to the interpretation of this Constitution. [(2) * * * *] (3) Where such a certificate is given, 3[***] any party in the case may appeal to the Supreme Court on the ground that any such question as aforesaid has been wrongly decided [***]. Explanation:- For t", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "133", "t": "Appellate jurisdiction of Supreme Court in appeals from High Courts in regard to", "c": "civil matters:- 4[(1) An appeal shall lie to the Supreme Court from any judgment, decree or final order in a civil proceeding of a High Court in the territory of India 5[if the High Court certifies under article 134A—] (a) that the case involves a substantial question of law of general importance; and (b) that in the opinion of the High Court the said question needs to be decided by the Supreme Court.]", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "134", "t": "Appellate jurisdiction of Supreme Court in regard to criminal matters", "c": "(1) An appeal shall lie to the Supreme Court from any judgment, final order or sentence in a criminal proceeding of a High Court in the territory of India if the High Court— (a) has on appeal reversed an order of acquittal of an accused person and sentenced him to death; or (b) has withdrawn for trial before itself any case from any court subordinate to its authority and has in such trial convicted the accused person and sentenced him to death; or (c) 1[certifies under article 134A] that the case is a fit one for appeal to the Supreme Court: Pr", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "135", "t": "Jurisdiction and powers of the Federal Court under existing law to be exercisable", "c": "by the Supreme Court.:- Until Parliament by law otherwise provides, the Supreme Court shall also have jurisdiction and powers with respect to any matter to which the provisions of article 133 or article 134 do not apply if jurisdiction and powers in relation to that matter were exercisable by the Federal Court immediately before the commencement of this Constitution under any existing law.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "136", "t": "Special leave to appeal by the Supreme Court", "c": "(1) Notwithstanding anything in this Chapter, the Supreme Court may, in its discretion, grant special leave to appeal from any judgment, decree, determination, sentence or order in any cause or matter passed or made by any court or tribunal in the territory of India. (2) Nothing in clause (1) shall apply to any judgment, determination, sentence or order passed or made by any court or tribunal constituted by or under any law relating to the Armed Forces.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "137", "t": "Review of judgments or orders by the Supreme Court", "c": "Subject to the provisions of any law made by Parliament or any rules made under article 145, the Supreme Court shall have power to review any judgment pronounced or order made by it.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "138", "t": "Enlargement of the jurisdiction of the Supreme Court", "c": "(1) The Supreme Court shall have such further jurisdiction and powers with respect to any of the matters in the Union List as Parliament may by law confer. (2) The Supreme Court shall have such further jurisdiction and powers with respect to any matter as the Government of India and the Government of any State may by special agreement confer, if Parliament by law provides for the exercise of such jurisdiction and powers by the Supreme Court.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "139", "t": "Conferment on the Supreme Court of powers to issue certain writs", "c": "Parliament may by law confer on the Supreme Court power to issue directions, orders or writs, including writs in the nature of habeas corpus, mandamus, prohibition, quo warranto and certiorari, or any of them, for any purposes other than those mentioned in clause (2) of article 32. [139A. Transfer of certain cases:- 2[(1) Where cases involving the same or substantially the same questions of law are pending before the Supreme Court and one or more High Courts or before two or more High Courts and the Supreme Court is satisfied on its own motion ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "140", "t": "Ancillary powers of Supreme Court", "c": "Parliament may by law make provision for conferring upon the Supreme Court such supplemental powers not inconsistent with any of the provisions of this Constitution as may appear to be necessary or desirable for the purpose of enabling the Court more effectively to exercise the jurisdiction conferred upon it by or under this Constitution.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "141", "t": "Law declared by Supreme Court to be binding on all courts", "c": "The law declared by the Supreme Court shall be binding on all courts within the territory of India.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "142", "t": "Enforcement of decrees and orders of Supreme Court and orders as to discovery,", "c": "etc.:- (1) The Supreme Court in the exercise of its jurisdiction may pass such decree or make such order as is necessary for doing complete justice in any cause or matter pending before it, and any decree so passed or order so made shall be enforceable throughout the territory of India in such manner as may be prescribed by or under any law made by Parliament and, until provision in that behalf is so made, in such manner as the President may by order1 prescribe. (2) Subject to the provisions of any law made in this behalf by Parliament, the Sup", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "143", "t": "Power of President to consult Supreme Court", "c": "(1) If at any time it appears to the President that a question of law or fact has arisen, or is likely to arise, which is of such a nature and of such public importance that it is expedient to obtain the opinion of the Supreme Court upon it, he may refer the question to that Court for consideration and the Court may, after such hearing as it thinks fit, report to the President its opinion thereon.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "144", "t": "Civil and judicial authorities to act in aid of the Supreme Court", "c": "All authorities, civil and judicial, in the territory of India shall act in aid of the Supreme Court. [144A. Special provisions as to disposal of questions relating to constitutional validity of laws.]:- Omitted by the Constitution (Forty-third Amendment) Act, 1977, s.5 (w.e.f. 13-41978).", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "145", "t": "Rules of Court, etc", "c": "(1) Subject to the provisions of any law made by Parliament, the Supreme Court may from time to time, with the approval of the President, make rules for regulating generally the practice and procedure of the Court including— (a) rules as to the persons practising before the Court; (b) rules as to the procedure for hearing appeals and other matters pertaining to appeals including the time within which appeals to the Court are to be entered; (c) rules as to the proceedings in the Court for the enforcement of any of the rights conferred by Part II", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "146", "t": "Officers and servants and the expenses of the Supreme Court", "c": "(1) Appointments of officers and servants of the Supreme Court shall be made by the Chief Justice of India or such other Judge or officer of the Court as he may direct: Provided that the President may by rule require that in such cases as may be specified in the rule, no person not already attached to the Court shall be appointed to any office connected with the Court, save after consultation with the Union Public Service Commission. (2) Subject to the provisions of any law made by Parliament, the conditions of service of officers and servants ", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "147", "t": "Interpretation", "c": "In this Chapter and in Chapter V of Part VI, references to any substantial question of law as to the interpretation of this Constitution shall be construed as including references to any substantial question of law as to the interpretation of the Government of India Act, 1935 (including any enactment amending or supplementing that Act), or of any Order in Council or order made thereunder, or of the Indian Independence Act, 1947, or of any order made thereunder. THE CONSTITUTION OF INDIA (Part V. — The Union) CHAPTER - V COMPTROLLER AND AUDITOR-", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "148", "t": "Comptroller and Auditor-General of India", "c": "(1) There shall be a Comptroller and Auditor-General of India who shall be appointed by the President by warrant under his hand and seal and shall only be removed from office in like manner and on the like grounds as a Judge of the Supreme Court. (2) Every person appointed to be the Comptroller and Auditor-General of India shall, before he enters upon his office, make and subscribe before the President, or some person appointed in that behalf by him, an oath or affirmation according to the form set out for the purpose in the Third Schedule. (3)", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "149", "t": "Duties and powers of the Comptroller and Auditor-General", "c": "The Comptroller and Auditor-General shall perform such duties and exercise such powers in relation to the accounts of the Union and of the States and of any other authority or body as may be prescribed by or under any law made by Parliament and, until provision in that behalf is so made, shall perform such duties and exercise such powers in relation to the accounts of the Union and of the States as were conferred on or exercisable by the Auditor-General of India immediately before the commencement of this Constitution in relation to the account", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "150", "t": "The Kerala Scheduled Tribes (Restriction on Transfer of Lands and", "c": "Restoration of Alienated Lands) Act, 1975 (Kerala Act 31 of 1975).", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "151", "t": "Audit reports", "c": "(1) The reports of the Comptroller and Auditor-General of India relating to the accounts of the Union shall be submitted to the President, who shall cause them to be laid before each House of Parliament. (2) The reports of the Comptroller and Auditor-General of India relating to the accounts of a State shall be submitted to the Governor 3[***] of the State, who shall cause them to be laid before the Legislature of the State.", "p": "V", "pn": "The Union", "clr": "#42A5F5"}, {"n": "152", "t": "Definition", "c": "In this Part, unless the context otherwise requires, the expression “State” [does not include the State of Jammu and Kashmir]. CHAPTER - II THE EXECUTIVE The Governor", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "153", "t": "Governors of States", "c": "There shall be a Governor for each State: [Provided that nothing in this article shall prevent the appointment of the same person as Governor for two or more States.]", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "154", "t": "Executive power of State", "c": "(1) The executive power of the State shall be vested in the Governor and shall be exercised by him either directly or through officers subordinate to him in accordance with this Constitution. (2) Nothing in this article shall— (a) be deemed to transfer to the Governor any functions conferred by any existing law on any other authority; or (b) prevent Parliament or the Legislature of the State from conferring by law functions on any authority subordinate to the Governor.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "155", "t": "Appointment of Governor", "c": "The Governor of a State shall be appointed by the President by warrant under his hand and seal.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "156", "t": "Term of office of Governor", "c": "(1) The Governor shall hold office during the pleasure of the President. (2) The Governor may, by writing under his hand addressed to the President, resign his office. (3) Subject to the foregoing provisions of this article, a Governor shall hold office for a term of five years from the date on which he enters upon his office: Provided that a Governor shall, notwithstanding the expiration of his term, continue to hold office until his successor enters upon his office.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "157", "t": "Qualifications for appointment as Governor", "c": "No person shall be eligible for appointment as Governor unless he is a citizen of India and has completed the age of thirtyfive years.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "158", "t": "Conditions of Governor's office", "c": "(1) The Governor shall not be a member of either House of Parliament or of a House of the Legislature of any State specified in the First Schedule, and if a member of either House of Parliament or of a House of the Legislature of any such State be appointed Governor, he shall be deemed to have vacated his seat in that House on the date on which he enters upon his office as Governor. (2) The Governor shall not hold any other office of profit. (3) The Governor shall be entitled without payment of rent to the use of his official residences and sha", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "159", "t": "Oath or affirmation by the Governor", "c": "Every Governor and every person discharging the functions of the Governor shall, before entering upon his office, make and subscribe in the presence of the Chief Justice of the High Court exercising jurisdiction in relation to the State, or, in his absence, the senior most Judge of that Court available, an oath or affirmation in the following form, that is to say— “I, A. B., do swear in the name of God that I will faithfully execute the solemnly affirm office of Governor (or discharge the functions of the Governor) of (name of the State)and wil", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "160", "t": "Discharge of the functions of the Governor in certain contingencies", "c": "The President may make such provision as he thinks fit for the discharge of the functions of the Governor of a State in any contingency not provided for in this Chapter.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "161", "t": "Power of Governor to grant pardons, etc., and to suspend, remit or commute", "c": "sentences in certain cases:- The Governor of a State shall have the power to grant pardons, reprieves, respites or remissions of punishment or to suspend, remit or commute the sentence of any person convicted of any.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "162", "t": "Extent of executive power of State", "c": "Subject to the provisions of this Constitution, the executive power of a State shall extend to the matters with respect to which the Legislature of the State has power to make laws: Provided that in any matter with respect to which the Legislature of a State and Parliament have power to make laws, the executive power of the State shall be subject to, and limited by, the executive power expressly conferred by this Constitution or by any law made by Parliament upon the Union or authorities thereof. THE CONSTITUTION OF INDIA (Part VI. — The States", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "163", "t": "Council of Ministers to aid and advise Governor", "c": "(1) There shall be a Council of Ministers with the Chief Minister at the head to aid and advise the Governor in the exercise of his functions, except in so far as he is by or under this Constitution required to exercise his functions or any of them in his discretion. (2) If any question arises whether any matter is or is not a matter as respects which the Governor is by or under this Constitution required to act in his discretion, the decision of the Governor in his discretion shall be final, and the validity of anything done by the Governor sh", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "164", "t": "Other provisions as to Ministers", "c": "(1) The Chief Minister shall be appointed by the Governor and the other Ministers shall be appointed by the Governor on the advice of the Chief Minister, and the Ministers shall hold office during the pleasure of the Governor: Provided that in the States of 1[Chhattisgarh, Jharkhand], Madhya Pradesh and [Odisha], there shall be a Minister in charge of tribal welfare who may in addition be in charge of the welfare of the Scheduled Castes and backward classes or any other work. [(1A) The total number of Ministers, including the Chief Minister, in", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "165", "t": "Advocate-General for the State", "c": "(1) The Governor of each State shall appoint a person who is qualified to be appointed a Judge of a High Court to be Advocate-General for the State. (2) It shall be the duty of the Advocate-General to give advice to the Government of the State upon such legal matters, and to perform such other duties of a legal character, as may from time to time be referred or assigned to him by the Governor, and to discharge the functions conferred on him by or under this Constitution or any other law for the time being in force. (3) The Advocate-General shal", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "166", "t": "Conduct of business of the Government of a State", "c": "(1) All executive action of the Government of a State shall be expressed to be taken in the name of the Governor. (2) Orders and other instruments made and executed in the name of the Governor shall be authenticated in such manner as may be specified in rules to be made by the Governor, and the validity of an order or instrument which is so authenticated shall not be called in question on the ground that it is not an order or instrument made or executed by the Governor. (3) The Governor shall make rules for the more convenient transaction of th", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "167", "t": "Duties of Chief Minister as respects the furnishing of information to Governor,", "c": "etc.:- It shall be the duty of the Chief Minister of each State— (a) to communicate to the Governor of the State all decisions of the Council of Ministers relating to the administration of the affairs of the State and proposals for legislation; (b) to furnish such information relating to the administration of the affairs of the State and proposals for legislation as the Governor may call for; and (c) if the Governor so requires, to submit for the consideration of the Council of Ministers any matter on which a decision has been taken by a Minist", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "168", "t": "Constitution of Legislatures in States", "c": "(1) For every State there shall be a Legislature which shall consist of the Governor, and— (a) in the States of 1[***] 2[Andhra Pradesh], Bihar, 3[***] 4[Madhya Pradesh], [***] 6[Maharashtra], 7[Karnataka], 8[***] 9[10Tamil Nadu, Telangana] 11[and Uttar Pradesh], two Houses; (b) in other States, one House. (2) Where there are two Houses of the Legislature of a State, one shall be known as the Legislative Council and the other as the Legislative Assembly, and where there is only one House, it shall be known as the Legislative Assembly.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "169", "t": "Abolition or creation of Legislative Councils in States", "c": "(1) Notwithstanding anything in article 168, Parliament may by law provide for the abolition of the Legislative Council of a State having such a Council or for the creation of such a Council in a State having no such Council, if the Legislative Assembly of the State passes a resolution to that effect by a majority of the total membership of the Assembly and by a majority of not less than two-thirds of the members of the Assembly present and voting.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "170", "t": "The Tamil Nadu Land Reforms (Fixation of Ceiling on Land) Third", "c": "Amendment Act, 1972 (Tamil Nadu Act 37 of 1972).", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "171", "t": "Composition of the Legislative Councils", "c": "(1) The total number of members in the Legislative Council of a State having such a Council shall not exceed 5[one third] of the total number of members in the Legislative Assembly of that State: Provided that the total number of members in the Legislative Council of a State shall in no case be less than forty. (2) Until Parliament by law otherwise provides, the composition of the Legislative Council of a State shall be as provided in clause (3). (3) Of the total number of members of the Legislative Council of a State— (a) as nearly as may be, ", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "172", "t": "Duration of State Legislatures", "c": "(1) Every Legislative Assembly of every State, unless sooner dissolved, shall continue for 1[five years] from the date appointed for its first meeting and no longer and the expiration of the said period of 1[five years] shall operate as a dissolution of the Assembly: Provided that the said period may, while a Proclamation of Emergency is in operation, be extended by Parliament by law for a period not exceeding one year at a time and not extending in any case beyond a period of six months after the Proclamation has ceased to operate. (2) The Leg", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "173", "t": "Qualification for membership of the State Legislature", "c": "A person shall not be qualified to be chosen to fill a seat in the Legislature of a State unless he— [(a) is a citizen of India, and makes and subscribes before some person authorised in that behalf by the Election Commission an oath or affirmation according to the form set out for the purpose in the Third Schedule;] (b) is, in the case of a seat in the Legislative Assembly, not less than twenty-five years of age and, in the case of a seat in the Legislative Council, not less than thirty years of age; and (c) possesses such other qualifications", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "174", "t": "The Tamil Nadu Land Reforms (Fixation of Ceiling on Land) Amendment Act,", "c": "1974 (Tamil Nadu Act 15 of 1974).", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "175", "t": "Right of Governor to address and send messages to the House or Houses", "c": "(1) The Governor may address the Legislative Assembly or, in the case of a State having a Legislative Council, either House of the Legislature of the State, or both Houses assembled together, and may for that purpose require the attendance of members.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "176", "t": "Special address by the Governor", "c": "(1) At the commencement of 1[the first session after each general election to the Legislative Assembly and at the commencement of the first session of each year], the Governor shall address the Legislative Assembly or, in the case of a State having a Legislative Council, both Houses assembled together and inform the Legislature of the causes of its summons. (2) Provision shall be made by the rules regulating the procedure of the House or either House for the allotment of time for discussion of the matters referred to in such address 2[***].", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "177", "t": "Rights of Ministers and Advocate-General as respects the Houses", "c": "Every Minister and the Advocate-General for a State shall have the right to speak in, and otherwise to take part in the proceedings of, the Legislative Assembly of the State or, in the case of a State having a Legislative Council, both Houses, and to speak in, and otherwise to take part in the proceedings of, any committee of the Legislature of which he may be named a member, but shall not, by virtue of this article, be entitled to vote. Officers of the State Legislature", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "178", "t": "The Speaker and Deputy Speaker of the Legislative Assembly", "c": "Every Legislative Assembly of a State shall, as soon as may be, choose two members of the Assembly to be respectively Speaker and Deputy Speaker thereof and, so often as the office of Speaker or Deputy Speaker becomes vacant, the Assembly shall choose another member to be Speaker or Deputy Speaker, as the case may be.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "179", "t": "Vacation and resignation of, and removal from, the offices of Speaker and Deputy", "c": "Speaker:- A member holding office as Speaker or Deputy Speaker of an Assembly— (a) shall vacate his office if he ceases to be a member of the Assembly; (b) may at any time by writing under his hand addressed, if such member is the Speaker, to the Deputy Speaker, and if such member is the Deputy Speaker, to the Speaker, resign his office; and", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "180", "t": "Power of the Deputy Speaker or other person to perform the duties of the office", "c": "of, or to act as, Speaker:- (1) While the office of Speaker is vacant, the duties of the office shall be performed by the Deputy Speaker or, if the office of Deputy Speaker is also vacant, by such member of the Assembly as the Governor may appoint for the purpose. (2) During the absence of the Speaker from any sitting of the Assembly the Deputy Speaker or, if he is also absent, such person as may be determined by the rules of procedure of the Assembly, or, if no such person is present, such other person as may be determined by the Assembly, sha", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "181", "t": "The Speaker or the Deputy Speaker not to preside while a resolution for his", "c": "removal from office is under consideration:- (1) At any sitting of the Legislative Assembly, while any resolution for the removal of the Speaker from his office is under consideration, the Speaker, or while any resolution for the removal of the Deputy Speaker from his office is under consideration, the Deputy Speaker, shall not, though he is present, preside, and the provisions of clause (2) of article 180 shall apply in relation to every such sitting as they apply in relation to a sitting from which the Speaker or, as the case may be, the Depu", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "182", "t": "The Chairman and Deputy Chairman of the Legislative Council", "c": "The Legislative Council of every State having such Council shall, as soon as may be, choose two members of the Council to be respectively Chairman and Deputy Chairman thereof and, so often as the office of Chairman or Deputy Chairman becomes vacant, the Council shall choose another member to be Chairman or Deputy Chairman, as the case may be. THE CONSTITUTION OF INDIA (Part VI. — The States)", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "183", "t": "Vacation and resignation of, and removal from, the offices of Chairman and", "c": "Deputy Chairman:- A member holding office as Chairman or Deputy Chairman of a Legislative Council — (a) shall vacate his office if he ceases to be a member of the Council; (b) may at any time by writing under his hand addressed, if such member is the Chairman, to the Deputy Chairman, and if such member is the Deputy Chairman, to the Chairman, resign his office; and (c) may be removed from his office by a resolution of the Council passed by a majority of all the then members of the Council: Provided that no resolution for the purpose of clause (", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "184", "t": "Power of the Deputy Chairman or other person to perform the duties of the office", "c": "of, or to act as, Chairman:- (1) While the office of Chairman is vacant, the duties of the office shall be performed by the Deputy Chairman or, if the office of Deputy Chairman is also vacant, by such member of the Council as the Governor may appoint for the purpose. (2) During the absence of the Chairman from any sitting of the Council the Deputy Chairman or, if he is also absent, such person as may be determined by the rules of procedure of the Council, or, if no such person is present, such other person as may be determined by the Council, s", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "185", "t": "The Chairman or the Deputy Chairman not to preside while a resolution for his", "c": "removal from office is under consideration:- (1) At any sitting of the Legislative Council, while any resolution for the removal of the Chairman from his office is under consideration, the Chairman, or while any resolution for the removal of the Deputy Chairman from his office is under consideration, the Deputy Chairman, shall not, though he is present, preside, and the provisions of clause ( 2) of article 184 shall apply in relation to every such sitting as they apply in relation to a sitting from which the Chairman or, as the case may be, the", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "186", "t": "Salaries and allowances of the Speaker and Deputy Speaker and the Chairman", "c": "and Deputy Chairman:- There shall be paid to the Speaker and the Deputy Speaker of the Legislative Assembly, and to the Chairman and the Deputy Chairman of the Legislative Council, such salaries and allowances as may be respectively fixed by the Legislature of the State by law and, until provision in that behalf is so made, such salaries and allowances as are specified in the Second Schedule.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "187", "t": "Secretariat of State Legislature", "c": "(1) The House or each House of the Legislature of a State shall have a separate secretarial staff: Provided that nothing in this clause shall, in the case of the Legislature of a State having a Legislative Council, be construed as preventing the creation of posts common to both Houses of such Legislature. (2) The Legislature of a State may by law regulate the recruitment, and the conditions of service of persons appointed, to the secretarial staff of the House or Houses of the Legislature of the State. (3) Until provision is made by the Legisla", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "188", "t": "Oath or affirmation by members", "c": "Every member of the Legislative Assembly or the Legislative Council of a State shall, before taking his seat, make and subscribe before the Governor, or some person appointed in that behalf by him, an oath or affirmation according to the form set out for the purpose in the Third Schedule.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "189", "t": "Voting in Houses, power of Houses to act notwithstanding vacancies and", "c": "quorum:- (1) Save as otherwise provided in this Constitution, all questions at any sitting of a House of the Legislature of a State shall be determined by a majority of votes of the members present and voting, other than the Speaker or Chairman, or person acting as such. The Speaker or Chairman, or person acting as such, shall not vote in the first instance, but shall have and exercise a casting vote in the case of an equality of votes. THE CONSTITUTION OF INDIA (Part VI. — The States) (2) A House of the Legislature of a State shall have power ", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "190", "t": "Vacation of seats", "c": "(1) No person shall be a member of both Houses of the Legislature of a State and provision shall be made by the Legislature of the State by law for the vacation by a person who is chosen a member of both Houses of his seat in one house or the other. (2) No person shall be a member of the Legislatures of two or more States specified in the First Schedule and if a person is chosen a member of the Legislatures of two or more such States, then, at the expiration of such period as may be specified in rules1 made by the President, that person‘s seat ", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "191", "t": "Disqualifications for membership", "c": "(1) A person shall be disqualified for being chosen as, and for being, a member of the Legislative Assembly or Legislative Council of a State— [(a) if he holds any office of profit under the Government of India or the Government of any State specified in the First Schedule, other than an office declared by the Legislature of the State by law not to disqualify its holder;] (b) if he is of unsound mind and stands so declared by a competent court; (c) if he is an undischarged insolvent; (d) if he is not a citizen of India, or has voluntarily acqui", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "192", "t": "The Bihar Land Reforms (Fixation of Ceiling Area and Acquisition of", "c": "Surplus Land) (Amendment) Act, 1976 (Bihar Act 22 of 1976).", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "193", "t": "Penalty for sitting and voting before making oath or affirmation under article 188", "c": "or when not qualified or when disqualified:- If a person sits or votes as a member of the Legislative Assembly or the Legislative Council of a State before he has complied with the requirements of article 188, or when he knows that he is not qualified or that he is disqualified for membership thereof, or that he is prohibited from so doing by the provisions of any law made by Parliament or the Legislature of the State, he shall be liable in respect of each day on which he so sits or votes to a penalty of five hundred rupees to be recovered as a", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "194", "t": "Powers, privileges, etc., of the Houses of Legislatures and of the members and", "c": "committees thereof:- (1) Subject to the provisions of this Constitution and to the rules and standing orders regulating the procedure of the Legislature, there shall be freedom of speech in the Legislature of every State.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "195", "t": "Salaries and allowances of members", "c": "Members of the Legislative Assembly and the Legislative Council of a State shall be entitled to receive such salaries and allowances as may from time to time be determined, by the Legislature of the State by law and, until provision in that respect is so made, salaries and allowances at such rates and upon such conditions as were immediately before the commencement of this Constitution applicable in the case of members of the Legislative Assembly of the corresponding Province. Legislative Procedure", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "196", "t": "Provisions as to introduction and passing of Bills", "c": "(1) Subject to the provisions of articles 198 and 207 with respect to Money Bills and other financial Bills, a Bill may originate in either House of the Legislature of a State which has a Legislative Council. (2) Subject to the provisions of articles 197 and 198, a Bill shall not be deemed to have been passed by the Houses of the Legislature of a State having a Legislative Council unless it has been agreed to by both Houses, either without amendment or with such amendments only as are agreed to by both Houses.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "197", "t": "Restriction on powers of Legislative Council as to Bills other than Money Bills:(1) If after a Bill has been passed by the Legislative Assembly of a State having a Legislative", "c": "Council and transmitted to the Legislative Council— (a) the Bill is rejected by the Council; or (b) more than three months elapse from the date on which the Bill is laid before the Council without the Bill being passed by it; or (c) the Bill is passed by the Council with amendments to which the Legislative Assembly does not agree; the Legislative Assembly may, subject to the rules regulating its procedure, pass the Bill again in the same or in any subsequent session with or without such amendments, if any, as have been made, suggested or agreed", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "198", "t": "Special procedure in respect of Money Bills", "c": "(1) A Money Bill shall not be introduced in a Legislative Council. (2) After a Money Bill has been passed by the Legislative Assembly of a State having a Legislative Council, it shall be transmitted to the Legislative Council for its recommendations, and the Legislative Council shall within a period of fourteen days from the date of its receipt of the Bill return the Bill to the Legislative Assembly with its recommendations, and the Legislative Assembly may thereupon either accept or reject all or any of the recommendations of the Legislative C", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "199", "t": "Definition of “Money Bills”", "c": "(1) For the purposes of this Chapter, a Bill shall be deemed to be a Money Bill if it contains only provisions dealing with all or any of the following matters, namely:— (a) the imposition, abolition, remission, alteration or regulation of any tax; (b) the regulation of the borrowing of money or the giving of any guarantee by the State, or the amendment of the law with respect to any financial obligations undertaken or to be undertaken by the State; (c) the custody of the Consolidated Fund or the Contingency Fund of the State, the payment of mo", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "200", "t": "Assent to Bills", "c": "When a Bill has been passed by the Legislative Assembly of a State or, in the case of a State having a Legislative Council, has been passed by both Houses of the Legislature of the State, it shall be presented to the Governor and the Governor shall declare either that he assents to the Bill or that he withholds assent therefrom or that he reserves the Bill for the consideration of the President: Provided that the Governor may, as soon as possible after the presentation to him of the Bill for assent, return the Bill if it is not a Money Bill tog", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "201", "t": "Bills reserved for consideration", "c": "When a Bill is reserved by a Governor for the consideration of the President, the President shall declare either that he assents to the Bill or that he withholds assent therefrom: Provided that, where the Bill is not a Money Bill, the President may direct the Governor to return the Bill to the House or, as the case may be, the Houses of the Legislature of the State together with such a message as is mentioned in the first proviso to article 200 and, when a Bill is so returned, the House or Houses shall reconsider it accordingly within a period ", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "202", "t": "Annual financial statement", "c": "(1) The Governor shall in respect of every financial year cause to be laid before the House or Houses of the Legislature of the State a statement of the estimated receipts and expenditure of the State for that year, in this Part referred to as the “annual financial statement”. (2) The estimates of expenditure embodied in the annual financial statement shall show separately— (a) the sums required to meet expenditure described by this Constitution as expenditure charged upon the Consolidated Fund of the State; and (b) the sums required to meet ot", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "203", "t": "Procedure in Legislature with respect to estimates", "c": "(1) So much of the estimates as relates to expenditure charged upon the Consolidated Fund of a State shall not be submitted to the vote of the Legislative Assembly, but nothing in this clause shall be construed as preventing the discussion in the Legislature of any of those estimates. (2) So much of the said estimates as relates to other expenditure shall be submitted in the form of demands for grants to the Legislative Assembly, and the Legislative Assembly shall have power to assent, or to refuse to assent, to any demand, or to assent to any ", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "204", "t": "Appropriation Bills", "c": "(1) As soon as may be after the grants under article 203 have been made by the Assembly, there shall be introduced a Bill to provide for the appropriation out of the Consolidated Fund of the State of all moneys required to meet— (a) the grants so made by the Assembly; and (b) the expenditure charged on the Consolidated Fund of the State but not exceeding in any case the amount shown in the statement previously laid before the House or Houses. (2) No amendment shall be proposed to any such Bill in the House or either House of the Legislature of ", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "205", "t": "Supplementary, additional or excess grants", "c": "(1) The Governor shall— (a) if the amount authorised by any law made in accordance with the provisions of article 204 to be expended for a particular service for the current financial year is found to be insufficient for the purposes of that year or when a need has arisen during the current financial year for supplementary or additional expenditure upon some new service not contemplated in the annual financial statement for that year, or (b) if any money has been spent on any service during a financial year in excess of the amount granted for t", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "206", "t": "Votes on account, votes of credit and exceptional grants", "c": "(1) Notwithstanding anything in the foregoing provisions of this Chapter, the Legislative Assembly of a State shall have power— (a) to make any grant in advance in respect of the estimated expenditure for a part of any financial year pending the completion of the procedure prescribed in article 203 for the voting of such grant and the passing of the law in accordance with the provisions of article 204 in relation to that expenditure; (b) to make a grant for meeting an unexpected demand upon the resources of the State when on account of the magn", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "207", "t": "Special provisions as to financial Bills", "c": "(1) A Bill or amendment making provision for any of the matters specified in sub-clauses (a) to (f) of clause (1) of article 199 shall not be introduced or moved except on the recommendation of the Governor, and a Bill making such provision shall not be introduced in a Legislative Council: Provided that no recommendation shall be required under this clause for the moving of an amendment making provision for the reduction or abolition of any tax. (2) A Bill or amendment shall not be deemed to make provision for any of the matters aforesaid by re", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "208", "t": "Rules of procedure", "c": "(1) A House of the Legislature of a State may make rules for regulating, subject to the provisions of this Constitution, its procedure and the conduct of its business. THE CONSTITUTION OF INDIA (Part VI. — The States) (2) Until rules are made under clause (1), the rules of procedure and standing orders in force immediately before the commencement of this Constitution with respect to the Legislature for the corresponding Province shall have effect in relation to the Legislature of the State subject to such modifications and adaptations as may be", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "209", "t": "Regulation by law of procedure in the Legislature of the State in relation to", "c": "financial business:- The Legislature of a State may, for the purpose of the timely completion of financial business, regulate by law the procedure of, and the conduct of business in, the House or Houses of the Legislature of the State in relation to any financial matter or to any Bill for the appropriation of moneys out of the Consolidated Fund of the State, and, if and so far as any provision of any law so made is inconsistent with any rule made by the House or either House of the Legislature of the State under clause (1) of article 208 or wit", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "210", "t": "Language to be used in the Legislature", "c": "(1) Notwithstanding anything in Part XVII, but subject to the provisions of article 348, business in the Legislature of a State shall be transacted in the official language or languages of the State or in Hindi or in English: Provided that the Speaker of the Legislative Assembly or Chairman of the Legislative Council, or person acting as such, as the case may be, may permit any member who cannot adequately express himself in any of the languages aforesaid to address the House in his mother-tongue. (2) Unless the Legislature of the State by law ", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "211", "t": "Restriction on discussion in the Legislature", "c": "No discussion shall take place in the Legislature of a State with respect to the conduct of any Judge of the Supreme Court or of a High Court in the discharge of his duties.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "212", "t": "Courts not to inquire into proceedings of the Legislature", "c": "(1) The validity of any proceedings in the Legislature of a State shall not be called in question on the ground of any alleged irregularity of procedure. (2) No officer or member of the Legislature of a State in whom powers are vested by or under this Constitution for regulating procedure or the conduct of business, or for maintaining order, in the Legislature shall be subject to the jurisdiction of any court in respect of the exercise by him of those powers. CHAPTER - IV LEGISLATIVE POWER OF THE GOVERNOR", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "213", "t": "Power of Governor to promulgate Ordinances during recess of Legislature", "c": "(1) If at any time, except when the Legislative Assembly of a State is in session, or where there is a Legislative Council in a State, except when both Houses of the Legislature are in session, the Governor is satisfied that circumstances exist which render it necessary for him to take immediate action, he may promulgate such Ordinances as the circumstances appear to him to require:", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "214", "t": "High Courts for States", "c": "2[***] There shall be a High Court for each State. [* * * *]", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "215", "t": "High Courts to be courts of record", "c": "Every High Court shall be a court of record and shall have all the powers of such a court including the power to punish for contempt of itself.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "216", "t": "Constitution of High Courts", "c": "Every High Court shall consist of a Chief Justice and such other Judges as the President may from time to time deem it necessary to appoint. [* * * *]", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "217", "t": "Appointment and conditions of the office of a Judge of a High Court", "c": "(1) Every Judge of a High Court shall be appointed by the President by warrant under his hand and seal [on the recommendation of the National Judicial Appointments Commission referred to in article 124A], and 6[shall hold office, in the the case of an additional or acting Judge, as provided in article 224, and in any other case, until he attains the age of 7[sixty-two years]:]", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "218", "t": "Application of certain provisions relating to Supreme Court to High Courts", "c": "The provisions of clauses (4) and (5) of article 124 shall apply in relation to a High Court as they apply in relation to the Supreme Court with the substitution of references to the High Court for references to the Supreme Court.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "219", "t": "Oath or affirmation by Judges of High Courts", "c": "Every person appointed to be a Judge of a High Court 4[***] shall, before he enters upon his office, make and subscribe before the Governor of the State, or some person appointed in that behalf by him, an oath or affirmation according to the form set out for the purpose in the Third Schedule.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "220", "t": "The Himachal Pradesh Transfer of Land (Regulation) Act, 1968 (Himachal", "c": "Pradesh Act 15 of 1969).", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "221", "t": "Salaries, etc., of Judges", "c": "2[(1) There shall be paid to the Judges of each High Court such salaries as may be determined by Parliament by law and, until provision in that behalf is so made, such salaries as are specified in the Second Schedule.] (2) Every Judge shall be entitled to such allowances and to such rights in respect of leave of absence and pension as may from time to time be determined by or under law made by Parliament and, until so determined, to such allowances and rights as are specified in the Second Schedule: Provided that neither the allowances of a Jud", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "222", "t": "Transfer of a Judge from one High Court to another", "c": "(1) The President may, 3[on the recommendation of the National Judicial Appointments Commission referred to in article 124A], transfer a Judge from one High Court to any other High Court 4[***].", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "223", "t": "Appointment of acting Chief Justice", "c": "When the office of Chief Justice of a High Court is vacant or when any such Chief Justice is, by reason of absence or otherwise, unable to perform the duties of his office, the duties of the office shall be performed by such one of the other Judges of the Court as the President may appoint for the purpose. [224. Appointment of additional and acting Judges:- (1) If by reason of any temporary increase in the business of a High Court or by reason of arrears of work therein, it appears to the President that the number of the Judges of that Court sh", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "224", "t": "The Kerala Land Reforms (Amendment) Act, 1981 (Kerala Act 19 of 1981)", "c": "", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "225", "t": "Jurisdiction of existing High Courts", "c": "Subject to the provisions of this Constitution and to the provisions of any law of the appropriate Legislature made by virtue of powers conferred on that Legislature by this Constitution, the jurisdiction of, and the law administered in, any existing High Court, and the respective powers of the Judges thereof in relation to the administration of justice in the Court, including any power to make rules of Court and to regulate the sittings of the Court and of members thereof sitting alone or in Division Courts, shall be the same as immediately be", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "226", "t": "The Madhya Pradesh Land Revenue Code (Amendment) Act, 1980 (Madhya", "c": "Pradesh Act 15 of 1980).", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "227", "t": "Power of superintendence over all courts by the High Court", "c": "3[(1) Every High Court shall have superintendence over all courts and tribunals throughout the territories in relation to which it exercises jurisdiction.] (2) Without prejudice to the generality of the foregoing provision, the High Court may— (a) call for returns from such courts; (b) make and issue general rules and prescribe forms for regulating the practice and proceedings of such courts; and (c) prescribe forms in which books, entries and accounts shall be kept by the officers of any such courts.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "228", "t": "Transfer of certain cases to High Court", "c": "If the High Court is satisfied that a case pending in a court subordinate to it involves a substantial question of law as to the interpretation of this Constitution the determination of which is necessary for the disposal of the case, 2[it shall withdraw the case and 3[***] may—] (a) either dispose of the case itself, or (b) determine the said question of law and return the case to the court from which the case has been so withdrawn together with a copy of its judgment on such question, and the said court shall on receipt thereof proceed to dis", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "229", "t": "Officers and servants and the expenses of High Courts", "c": "(1) Appointments of officers and servants of a High Court shall be made by the Chief Justice of the Court or such other Judge or officer of the Court as he may direct: Provided that the Governor of the State 1[***] may by rule require that in such cases as may be specified in the rule no person not already attached to the Court shall be appointed to any office connected with the Court save after consultation with the State Public Service Commission. (2) Subject to the provisions of any law made by the Legislature of the State, the conditions of", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "230", "t": "The Madhya Pradesh Ceiling on Agricultural Holdings (Amendment) Act,", "c": "1989 (Madhya Pradesh Act 8 of 1989).", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "231", "t": "Establishment of a common High Court for two or more States:(1) Notwithstanding anything contained in the preceding provisions of this Chapter,", "c": "Parliament may by law establish a common High Court for two or more States or for two or more States and a Union territory. (2) In relation to any such High Court,— [(a) * * * *] (b) the reference in article 227 to the Governor shall, in relation to any rules, forms or tables for subordinate courts, be construed as a reference to the Governor of the State in which the subordinate courts are situate; and (c) the references in articles 219 and 229 to the State shall be construed as a reference to the State in which the High Court has its principa", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "232", "t": "The Maharashtra Land Revenue Code and the Maharashtra Restoration of", "c": "Lands to Scheduled Tribes (Second Amendment) Act, 1976 (Maharashtra Act 30 of 1977).", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "233", "t": "Appointment of district judges", "c": "(1) Appointments of persons to be, and the posting and promotion of, district judges in any State shall be made by the Governor of the State in consultation with the High Court exercising jurisdiction in relation to such State.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "234", "t": "Recruitment of persons other than district judges to the judicial service:Appointments of persons other than district judges to the judicial service of a State shall be", "c": "made by the Governor of the State in accordance with rules made by him in that behalf after consultation with the State Public Service Commission and with the High Court exercising jurisdiction in relation to such State.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "235", "t": "Control over subordinate courts", "c": "The control over district courts and courts subordinate thereto including the posting and promotion of, and the grant of leave to, persons belonging to the judicial service of a State and holding any post inferior to the post of district judge shall be vested in the High Court, but nothing in this article shall be construed as taking away from any such person any right of appeal which he may have under the law regulating the conditions of his service or as authorising the High Court to deal with him otherwise than in accordance with the conditi", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "236", "t": "Interpretation", "c": "In this Chapter— (a) the expression “district judge” includes judge of a city civil court, additional district judge, joint district judge, assistant district judge, chief judge of a small cause court, chief presidency magistrate, additional chief presidency magistrate, sessions judge, additional sessions judge and assistant sessions Judge; (b) the expression “judicial service” means a service consisting exclusively of persons intended to fill the post of district judge and other civil judicial posts inferior to the post of district judge.", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "237", "t": "Application of the provisions of this Chapter to certain class or classes of", "c": "magistrates:- The Governor may by public notification direct that the foregoing provisions of this Chapter and any rules made thereunder shall with effect from such date as may be fixed by him in that behalf apply in relation to any class or classes of magistrates in the State as they apply in relation to persons appointed to the judicial service of the State subject to such exceptions and modifications as may be specified in the notification. THE CONSTITUTION OF INDIA PART - VII. [The States in Part B of the First Schedule].Omitted by the Cons", "p": "VI", "pn": "The States", "clr": "#26C6DA"}, {"n": "238", "t": "The Rajasthan Colonisation (Amendment) Act, 1984 (Rajasthan Act 12 of", "c": "1984).", "p": "VII", "pn": "States in Part B", "clr": "#78909C"}, {"n": "239", "t": "The Rajasthan Tenancy (Amendment) Act, 1984 (Rajasthan Act 13 of 1984)", "c": "", "p": "VIII", "pn": "Union Territories", "clr": "#66BB6A"}, {"n": "239AB", "t": "Provision in case of failure of constitutional machinery", "c": "If the President, on receipt of a report from the Lieutenant Governor or otherwise, is satisfied— (a) that a situation has arisen in which the administration of the National Capital Territory cannot be carried on in accordance with the provisions of article 239AA or of any law made in pursuance of that article; or (b) that for the proper administration of the National Capital Territory it is necessary or expedient so to do, the President may by order suspend the operation of any provision of article 239AA or of all or any of the provisions of a", "p": "VIII", "pn": "Union Territories", "clr": "#66BB6A"}, {"n": "240", "t": "The Rajasthan Tenancy (Amendment) Act, 1987 (Rajasthan Act 21 of 1987)", "c": "", "p": "VIII", "pn": "Union Territories", "clr": "#66BB6A"}, {"n": "241", "t": "High Courts for Union territories— (1) Parliament may by law constitute a High", "c": "Court for a 3[Union territory] or declare any court in any 4[such territory] to be a High Court Court for all or any of the purposes of this Constitution. (2) The provisions of Chapter V of Part VI shall apply in relation to every High Court referred to in clause (1) as they apply in relation to a High Court referred to in article 214 subject to such modifications or exceptions as Parliament may by law provide. [(3) Subject to the provisions of this Constitution and to the provisions of any law of the appropriate Legislature made by virtue of p", "p": "VIII", "pn": "Union Territories", "clr": "#66BB6A"}, {"n": "242", "t": "The Tamil Nadu Land Reforms (Fixation of Ceiling on Land) Amendment Act,", "c": "1980 (Tamil Nadu Act 21 of 1980).", "p": "VIII", "pn": "Union Territories", "clr": "#66BB6A"}, {"n": "243", "t": "Definitions", "c": "In this Part, unless the context otherwise requires,— (a) “district” means a district in a State; (b) “Gram Sabha” means a body consisting of persons registered in the electoral rolls relating to a village comprised within the area of Panchayat at the village level; (c) “intermediate level” means a level between the village and district levels specified by the Governor of a State by public notification to be the intermediate level for the purposes of this Part; (d) “Panchayat” means an institution (by whatever name called) of self-government co", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243A", "t": "Gram Sabha", "c": "A Gram Sabha may exercise such powers and perform such functions at the village level as the Legislature of a State may, by law, provide.", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243B", "t": "Constitution of Panchayats", "c": "(1) There shall be constituted in every State, Panchayats at the village, intermediate and district levels in accordance with the provisions of this Part. (2) Notwithstanding anything in clause (1), Panchayats at the intermediate level may not be constituted in a State having a population not exceeding twenty lakhs.", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243C", "t": "Composition of Panchayats", "c": "(1) Subject to the provisions of this Part, the Legislature of a State may, by law, make provisions with respect to the composition of Panchayats:", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243D", "t": "Reservation of seats", "c": "(1) Seats shall be reserved for— (a) the Scheduled Castes; and (b) the Scheduled Tribes, in every Panchayat and the number of seats so reserved shall bear, as nearly as may be, the same proportion to the total number of seats to be filled by direct election in that Panchayat as the population of the Scheduled Castes in that Panchayat area or of the Scheduled Tribes in that Panchayat area bears to the total population of that area and such seats may be allotted by rotation to different constituencies in a Panchayat. (2) Not less than one-third o", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243E", "t": "Duration of Panchayats, etc", "c": "(1) Every Panchayat, unless sooner dissolved under any law for the time being in force, shall continue for five years from the date appointed for its first meeting and no longer. (2) No amendment of any law for the time being in force shall have the effect of causing dissolution of a Panchayat at any level, which is functioning immediately before such amendment, till the expiration of its duration specified in clause (1). (3) An election to constitute a Panchayat shall be completed— (a) before the expiry of its duration specified in clause (1);", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243F", "t": "Disqualifications for membership", "c": "(1) A person shall be disqualified for being chosen as, and for being, a member of a Panchayat— (a) if he is so disqualified by or under any law for the time being in force for the purposes of elections to the Legislature of the State concerned: Provided that no person shall be disqualified on the ground that he is less than twenty-five years of age, if he has attained the age of twenty-one years; (b) if he is so disqualified by or under any law made by the Legislature of the State. (2) If any question arises as to whether a member of a Panchay", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243G", "t": "Powers, authority and responsibilities of Panchayats", "c": "Subject to the provisions of this Constitution, the Legislature of a State may, by law, endow the Panchayats with such powers and authority as may be necessary to enable them to function as institutions of selfgovernment and such law may contain provisions for the devolution of powers and responsibilities upon Panchayats at the appropriate level, subject to such conditions as may be specified therein, with respect to— (a) the preparation of plans for economic development and social justice; (b) the implementation of schemes for economic develop", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243H", "t": "Powers to impose taxes by, and Funds of, the Panchayats", "c": "The Legislature of a State may, by law,— (a) authorise a Panchayat to levy, collect and appropriate such taxes, duties, tolls and fees in accordance with such procedure and subject to such limits; (b) assign to a Panchayat such taxes, duties, tolls and fees levied and collected by the State Government for such purposes and subject to such conditions and limits; (c) provide for making such grants-in-aid to the Panchayats from the Consolidated Fund of the State; and (d) provide for constitution of such Funds for crediting all moneys received, res", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243J", "t": "Audit of accounts of Panchayats", "c": "The Legislature of a State may, by law, make provisions with respect to the maintenance of accounts by the Panchayats and the auditing of such accounts.", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243K", "t": "Elections to the Panchayats", "c": "(1) The superintendence, direction and control of the preparation of electoral rolls for, and the conduct of, all elections to the Panchayats shall be vested in a State Election Commission consisting of a State Election Commissioner to be appointed by the Governor. (2) Subject to the provisions of any law made by the Legislature of a State, the conditions of service and tenure of office of the State Election Commissioner shall be such as the Governor may by rule determine: Provided that the State Election Commissioner shall not be removed from ", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243L", "t": "Application to Union territories", "c": "The provisions of this Part shall apply to the Union territories and shall, in their application to a Union territory, have effect as if the references to the Governor of a State were references to the Administrator of the Union territory appointed under article 239 and references to the Legislature or the legislative Assembly of a State were references, in relation to a Union territory having a Legislative Assembly, to that Legislative Assembly: Provided that the President may, by public notification, direct that the provisions of this Part sh", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243M", "t": "Part not to apply to certain areas", "c": "(1) Nothing in this Part shall apply to the Scheduled Areas referred to in clause (1), and the tribal areas referred to in clause (2), of article 244. (2) Nothing in this Part shall apply to— (a) the States of Nagaland, Meghalaya and Mizoram; (b) the hill areas in the State of Manipur for which District Councils exist under any law for the time being in force. (3) Nothing in this Part— (a) relating to Panchayats at the district level shall apply to the hill areas of the District of Darjeeling in the State of West Bengal for which Darjeeling Gor", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243N", "t": "Continuance of existing laws and Panchayats", "c": "Notwithstanding anything in this Part, any provision of any law relating to Panchayats in force in a State immediately before the commencement of the Constitution (Seventy-third Amendment) Act, 1992, which is inconsistent with the provisions of this Part, shall continue to be in force until amended or repealed by a competent Legislature or other competent Provided that all the Panchayats existing immediately before such commencement shall continue till the expiration of their duration, unless sooner dissolved by a resolution passed to that effe", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243P", "t": "Definitions", "c": "In this Part, unless the context otherwise requires,— (a) “Committee” means a Committee constituted under article 243S; (b) “district” means a district in a State; (c) “Metropolitan area” means an area having a population of ten lakhs or more, comprised in one or more districts and consisting of two or more Municipalities or Panchayats or other contiguous areas, specified by the Governor by public notification to be a Metropolitan area for the purposes of this Part; (d) “Municipal area” means the territorial area of a Municipality as is notifie", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243Q", "t": "Constitution of Municipalities", "c": "(1) There shall be constituted in every State,— (a) a Nagar Panchayat (by whatever name called) for a transitional area, that is to say, an area in transition from a rural area to an urban area; (b) a Municipal Council for a smaller urban area; and (c) a Municipal Corporation for a larger urban area, in accordance with the provisions of this Part: Provided that a Municipality under this clause may not be constituted in such urban area or part thereof as the Governor may, having regard to the size of the area and the municipal services being pro", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243R", "t": "Composition of Municipalities", "c": "(1) Save as provided in clause (2), all the seats in a Municipality shall be filled by persons chosen by direct election from the territorial constituencies in the Municipal area and for this purpose each Municipal area shall be divided into territorial constituencies to be known as wards. (2) The Legislature of a State may, by law, provide— (a) for the representation in a Municipality of— (i) persons having special knowledge or experience in Municipal administration; (ii) the members of the House of the People and the members of the Legislativ", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243S", "t": "Constitution and composition of Wards Committees, etc", "c": "(1) There shall be constituted Wards Committees, consisting of one or more wards, within the territorial area of a Municipality having a population of three lakhs or more. (2) The Legislature of a State may, by law, make provision with respect to— (a) the composition and the territorial area of a Wards Committee; (b) the manner in which the seats in a Wards Committee shall be filled. THE CONSTITUTION OF INDIA (Part IXA. - The Municipalities) (3) A member of a Municipality representing a ward within the territorial area of the Wards Committee sh", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243T", "t": "Reservation of seats", "c": "(1) Seats shall be reserved for the Scheduled Castes and the Scheduled Tribes in every Municipality and the number of seats so reserved shall bear, as nearly as may be, the same proportion to the total number of seats to be filled by direct election in that Municipality as the population of the Scheduled Castes in the Municipal area or of the Scheduled Tribes in the Municipal area bears to the total population of that area and such seats may be allotted by rotation to different constituencies in a Municipality. (2) Not less than one-third of th", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243U", "t": "Duration of Municipalities, etc", "c": "(1) Every Municipality, unless sooner dissolved under any law for the time being in force, shall continue for five years from the date appointed for its first meeting and no longer: Provided that a Municipality shall be given a reasonable opportunity of being heard before its dissolution. (2) No amendment of any law for the time being in force shall have the effect of causing dissolution of a Municipality at any level, which is functioning immediately before such amendment, till the expiration of its duration specified in clause (1). (3) An ele", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243V", "t": "Disqualifications for membership", "c": "(1) A person shall be disqualified for being chosen as, and for being, a member of a Municipality— (a) if he is so disqualified by or under any law for the time being in force for the purposes of elections to the Legislature of the State concerned: Provided that no person shall be disqualified on the ground that he is less than twenty-five years of age, if he has attained the age of twenty-one years; (b) if he is so disqualified by or under any law made by the Legislature of the State. THE CONSTITUTION OF INDIA (Part IXA. - The Municipalities) ", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243W", "t": "Powers, authority and responsibilities of Municipalities, etc", "c": "Subject to the provisions of this Constitution, the Legislature of a State may, by law, endow— (a) the Municipalities with such powers and authority as may be necessary to enable them to function as institutions of self-government and such law may contain provisions for the devolution of powers and responsibilities upon Municipalities, subject to such conditions as may be specified therein, with respect to— (i) the preparation of plans for economic development and social justice; (ii) the performance of functions and the implementation of schem", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243X", "t": "Power to impose taxes by, and Funds of, the Municipalities", "c": "The Legislature of a State may, by law,— (a) authorise a Municipality to levy, collect and appropriate such taxes, duties, tolls and fees in accordance with such procedure and subject to such limits; (b) assign to a Municipality such taxes, duties, tolls and fees levied and collected by the State Government for such purposes and subject to such conditions and limits; (c) provide for making such grants-in-aid to the Municipalities from the Consolidated Fund of the State; and (d) provide for constitution of such Funds for crediting all moneys rec", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243Y", "t": "Finance Commission", "c": "(1) The Finance Commission constituted under article 243-I shall also review the financial position of the Municipalities and make recommendations to the Governor as to — (a) the principles which should govern— (i) the distribution between the State and the Municipalities of the net proceeds of the taxes, duties, tolls and fees leviable by the State, which may be divided between them under this Part and the allocation between the Municipalities at all levels of their respective shares of such proceeds; (ii) the determination of the taxes, dutie", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243Z", "t": "Audit of accounts of Municipalities", "c": "The Legislature of a State may, by law, make provisions with respect to the maintenance of accounts by the Municipalities and the auditing of such accounts.", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZA", "t": "Elections to the Municipalities", "c": "(1) The superintendence, direction and control of the preparation of electoral rolls for, and the conduct of, all elections to the Municipalities shall be vested in the State Election Commission referred to in article 243K. (2) Subject to the provisions of this Constitution, the Legislature of a State may, by law, make provision with respect to all matters relating to, or in connection with, elections to the Municipalities.", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZB", "t": "Application to Union territories", "c": "The provisions of this Part shall apply to the Union territories and shall, in their application to a Union territory, have effect as if the references to the Governor of a State were references to the Administrator of the Union territory appointed under article 239 and references to the Legislature or the Legislative Assembly of a State were references in relation to a Union territory having a Legislative Assembly, to that Legislative Assembly: THE CONSTITUTION OF INDIA (Part IXA. - The Municipalities) Provided that the President may, by publi", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZC", "t": "Part not to apply to certain areas", "c": "(1) Nothing in this Part shall apply to the Scheduled Areas referred to in clause (1), and the tribal areas referred to in clause (2) of article 244. (2) Nothing in this Part shall be construed to affect the functions and powers of the Darjeeling Gorkha Hill Council constituted under any law for the time being in force for the hill areas of the district of Darjeeling in the State of West Bengal. (3) Notwithstanding anything in this Constitution, Parliament may, by law, extend the provisions of this Part to the Scheduled Areas and the tribal are", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZD", "t": "Committee for district planning", "c": "(1) There shall be constituted in every State at the district level a District Planning Committee to consolidate the plans prepared by the Panchayats and the Municipalities in the district and to prepare a draft development plan for the district as a whole. (2) The Legislature of a State may, by law, make provision with respect to— (a) the composition of the District Planning Committees; (b) the manner in which the seats in such Committees shall be filled: Provided that not less than four-fifths of the total number of members of such Committee ", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZE", "t": "Committee for Metropolitan planning", "c": "(1) There shall be constituted in every Metropolitan area a Metropolitan Planning Committee to prepare a draft development plan for the Metropolitan area as a whole. (2) The Legislature of a State may, by law, make provision with respect to— (a) the composition of the Metropolitan Planning Committees; (b) the manner in which the seats in such Committees shall be filled: Provided that not less than two-thirds of the members of such Committee shall be elected by, and from amongst, the elected members of the Municipalities and Chairpersons of the ", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZF", "t": "Continuance of existing laws and Municipalities", "c": "Notwithstanding anything in this Part, any provision of any law relating to Municipalities in force in a State immediately before the commencement of the Constitution (Seventy-fourth Amendment) Act, 1992, which is inconsistent with the provisions of this Part, shall continue to be in force until amended or repealed by a competent Legislature or other competent authority or until the expiration of one year from such commencement, whichever is earlier: Provided that all the Municipalities existing immediately before such commencement shall contin", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZG", "t": "Bar to interference by courts in electoral matters", "c": "Notwithstanding anything in this Constitution,— (a) the validity of any law relating to the delimitation of constituencies or the allotment of seats to such constituencies, made or purporting to be made under article 243ZA shall not be called in question in any court; (b) no election to any Municipality shall be called in question except by an election petition presented to such authority and in such manner as is provided for by or under any law made by the Legislature of a State.] THE CONSTITUTION OF INDIA [PART - IXB THE CO-OPERATIVE SOCIETIE", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZH", "t": "Definitions", "c": "In this Part, unless the context otherwise requires,— (a) “authorised person” means a person referred to as such in article 243ZQ; (b) “board” means the board of directors or the governing body of a co-operative society, by whatever name called, to which the direction and control of the management of the affairs of a society is entrusted to; (c) “co-operative society” means a society registered or deemed to be registered under any law relating to co-operative societies for the time being in force in any State; (d) “multi-State co-operative soci", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZI", "t": "Incorporation of co-operative societies", "c": "Subject to the provisions of this Part, the Legislature of a State may, by law, make provisions with respect to the incorporation, regulation and winding up of co-operative societies based on the principles of voluntary formation, democratic member-control, member-economic participation and autonomous functioning.", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZJ", "t": "Number and term of members of board and its office bearers", "c": "(1) The board shall consist of such number of directors as may be provided by the Legislature of a State, by law: Provided that the maximum number of directors of a co-operative society shall not exceed twenty-one: Provided further that the Legislature of a State shall, by law, provide for the reservation of one seat for the Scheduled Castes or the Scheduled Tribes and two seats for women on board of every co-operative society consisting of individuals as members and having members from such class of category of persons. (2) The term of office ", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZK", "t": "Election of members of board", "c": "(1) Notwithstanding anything contained in any law made by the Legislature of a State, the election of a board shall be conducted before the expiry of the term of the board so as to ensure that the newly elected members of the board assume office immediately on the expiry of the term of the office of members of the outgoing board. THE CONSTITUTION OF INDIA (Part IXB. - The Co-operative Societies) (2) The superintendence, direction and control of the preparation of electoral rolls for, and the conduct of, all elections to a co-operative society s", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZL", "t": "Supersession and suspension of board and interim management", "c": "(1) Notwithstanding anything contained in any law for the time being in force, no board shall be superseded or kept under supersession for a period exceeding six months: Provided that the board may be superseded or kept under suspension in a case— (i) of its persistent default; or (ii) of negligence in the performance of its duties; or (iii) the board has committed any act prejudicial to the interests of the co-operative society or its members; or (iv) there is stalemate in the constitution or functions of the board; or (v) the authority or bod", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZM", "t": "Audit of accounts of co-operative societies", "c": "(1) The Legislature of a State may, by law, make provisions with respect to the maintenance of accounts by the co-operative societies and the auditing of such accounts at least once in each financial year. (2) The Legislature of a State shall, by law, lay down the minimum qualifications and experience of auditors and auditing firms that shall be eligible for auditing accounts of the co-operative societies. (3) Every co-operative society shall cause to be audited by an auditor or auditing firms referred to in clause (2) appointed by the general ", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZN", "t": "Convening of general body meetings", "c": "The Legislature of a State may, by law, make provisions that the annual general body meeting of every co-operative society shall be convened within a period of six months of close of the financial year to transact the business as may be provided in such law.", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZO", "t": "Right of a member to get information", "c": "(1) The Legislature of a State may, by law, provide for access to every member of a co-operative society to the books, information and accounts of the co¬operative society kept in regular transaction of its business with such members. (2) The Legislature of a State may, by law, make provisions to ensure the participation of members of the management of the co-operative society providing minimum requirement of attending meetings by the members and utilising the minimum level of services as may be provided in such law. (3) The Legislature of a St", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZP", "t": "Returns", "c": "(1) Every co-operative society shall file returns, within six months of the close of every financial year, to the authority designated by the State Government including the following matters, namely:— (a) annual report of its activities; (b) its audited statement of accounts; (c) plan for surplus disposal as approved by the general body of the co-operative society; (d) list of amendments to the bye-laws of the co-operative society, if any; (e) declaration regarding date of holding of its general body meeting and conduct of elections when due; a", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZQ", "t": "Offences and penalties", "c": "(1) The Legislature of a State may, by law, make provisions for the offences relating to the co-operative societies and penalties for such offences. (2) A law made by the Legislature of a State under clause (1) shall include the commission of the following act or omission as offences, namely:— (a) a co-operative society or an officer or member thereof wilfully makes a false return or furnishes false information, or any person wilfully not furnishes any information required from him by a person authorised in this behalf under the provisions of t", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZR", "t": "Application to multi-State co-operative societies", "c": "The provisions of this Part shall apply to the multi-State co-operative societies subject to the modification that any reference to “Legislature of a State”, “State Act” or State Government” shall be construed as a reference to “Parliament”, “Central Act” or “the Central Government” respectively.", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZS", "t": "Application to Union territories", "c": "The provisions of this Part shall apply to the Union territories and shall, in their application to a Union territory, having no Legislative Assembly as if the references to the Legislature of a State were a reference to the administrator thereof appointed under article 239 and, in relation to a Union territory having a Legislative Assembly, to that Legislative Assembly: Provided that the President may, by notification in the Official Gazette, direct that the provisions of this Part shall not apply to any Union territory or part thereof as he m", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "243ZT", "t": "Continuance of existing laws", "c": "Notwithstanding anything in this Part, any provision of any law relating to co-operative societies in force in a State immediately before the commencement of the Constitution (Ninety-seventh Amendment) Act, 2011, which is inconsistent with the provisions of this Part, shall continue to be in force until amended or repealed by a competent Legislature or other competent authority or until the expiration of one year from such commencement, whichever is less.] THE CONSTITUTION OF INDIA PART - X THE SCHEDULED AND TRIBAL AREAS", "p": "IX", "pn": "Panchayats & Municipalities", "clr": "#AB47BC"}, {"n": "244", "t": "Administration of Scheduled Areas and tribal areas", "c": "(1) The provisions of the Fifth Schedule shall apply to the administration and control of the Scheduled Areas and Scheduled Tribes in any State 1[***] other than 2[the States of Assam, 3[4[Meghalaya, Tripura and Mizoram.]]] (2) The provisions of the Sixth Schedule shall apply to the administration of the tribal areas in the States of Assam, 3[5[Meghalaya, Tripura and Mizoram]. [244A. Formation of an autonomous State comprising certain tribal areas in Assam and creation of local Legislature or Council of Ministers or both therefor:(1) Notwithsta", "p": "X", "pn": "Scheduled & Tribal Areas", "clr": "#8D6E63"}, {"n": "245", "t": "Extent of laws made by Parliament and by the Legislatures of States", "c": "(1) Subject to the provisions of this Constitution, Parliament may make laws for the whole or any part of the territory of India, and the Legislature of a State may make laws for the whole or any part of the State. (2) No law made by Parliament shall be deemed to be invalid on the ground that it would have extra-territorial operation.", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "246", "t": "Subject-matter of laws made by Parliament and by the Legislatures of States", "c": "(1) Notwithstanding anything in clauses (2) and (3), Parliament has exclusive power to make laws with respect to any of the matters enumerated in List I in the Seventh Schedule (in this Constitution referred to as the “Union List”). (2) Notwithstanding anything in clause (3), Parliament, and, subject to clause (1), the Legislature of any State 1[***] also, have power to make laws with respect to any of the matters enumerated in List III in the Seventh Schedule (in this Constitution referred to as the “Concurrent List”). (3) Subject to clauses (", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "247", "t": "Power of Parliament to provide for the establishment of certain additional", "c": "courts:- Notwithstanding anything in this Chapter, Parliament may by law provide for the establishment of any additional courts for the better administration of laws made by Parliament or of any existing laws with respect to a matter enumerated in the Union List.", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "248", "t": "Residuary powers of legislation", "c": "(1) 2[Subject to article 246A, Parliament] has exclusive power to make any law with respect to any matter not enumerated in the Concurrent List or State List. (2) Such power shall include the power of making any law imposing a tax not mentioned in either of those Lists.", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "249", "t": "Power of Parliament to legislate with respect to a matter in the State List in the", "c": "national interest:- (1) Notwithstanding anything in the foregoing provisions of this Chapter, if the Council of States has declared by resolution supported by not less than two-thirds of the members present and voting that it is necessary or expedient in the national interest that Parliament should make laws with respect to 3[goods and services tax provided under article 246A or] any matter enumerated in the State List specified in the resolution, it shall be lawful for Parliament to make laws for the whole or any part of the territory of India", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "250", "t": "Power of Parliament to legislate with respect to any matter in the State List if a", "c": "Proclamation of Emergency is in operation:- (1) Notwithstanding anything in this Chapter, Parliament shall, while a Proclamation of Emergency is in operation, have power to make laws for the whole or any part of the territory of India with respect to 1[goods and services tax provided under article 246A or]any of the matters enumerated in the State List. (2) A law made by Parliament which Parliament would not but for the issue of a Proclamation of Emergency have been competent to make shall, to the extent of the incompetency, cease to have effec", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "251", "t": "Inconsistency between laws made by Parliament under articles 249 and 250 and", "c": "laws made by the Legislatures of States:- Nothing in articles 249 and 250 shall restrict the power of the Legislature of a State to make any law which under this Constitution it has power to make, but if any provision of a law made by the Legislature of a State is repugnant to any provision of a law made by Parliament which Parliament has under either of the said articles power to make, the law made by Parliament, whether passed before or after the law made by the Legislature of the State, shall prevail, and the law made by the Legislature of t", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "252", "t": "Power of Parliament to legislate for two or more States by consent and adoption", "c": "of such legislation by any other State:- (1) If it appears to the Legislatures of two or more States to be desirable that any of the matters with respect to which Parliament has no power to make laws for the States except as provided in articles 249 and 250 should be regulated in such States by Parliament by law, and if resolutions to that effect are passed by all the Houses of the Legislatures of those States, it shall be lawful for Parliament to pass an act for regulating that matter accordingly, and any Act so passed shall apply to such Stat", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "253", "t": "Legislation for giving effect to international agreements", "c": "Notwithstanding anything in the foregoing provisions of this Chapter, Parliament has power to make any law for the whole or any part of the territory of India for implementing any treaty, agreement or convention with any other country or countries or any decision made at any international conference, association or other body. THE CONSTITUTION OF INDIA (Part XI. - Relations Between The Union And The States)", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "254", "t": "Inconsistency between laws made by Parliament and laws made by the", "c": "Legislatures of States:- (1) If any provision of a law made by the Legislature of a State is repugnant to any provision of a law made by Parliament which Parliament is competent to enact, or to any provision of an existing law with respect to one of the matters enumerated in the Concurrent List, then, subject to the provisions of clause (2), the law made by Parliament, whether passed before or after the law made by the Legislature of such State, or, as the case may be, the existing law, shall prevail and the law made by the Legislature of the S", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "255", "t": "Requirements as to recommendations and previous sanctions to be regarded as", "c": "matters of procedure only:- No Act of Parliament or of the Legislature of a State 1[***], and no provision in any such Act, shall be invalid by reason only that some recommendation or previous sanction required by this Constitution was not given, if assent to that Act was given— (a) where the recommendation required was that of the Governor, either by the Governor or by the President; (b) where the recommendation required was that of the Rajpramukh, either by the Rajpramukh or by the President; (c) where the recommendation or previous sanction ", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "256", "t": "Obligation of States and the Union", "c": "The executive power of every State shall be so exercised as to ensure compliance with the laws made by Parliament and any existing laws which apply in that State, and the executive power of the Union shall extend to the giving of such directions to a State as may appear to the Government of India to be necessary for that purpose.", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "257", "t": "Control of the Union over States in certain cases", "c": "(1) The executive power of every State shall be so exercised as not to impede or prejudice the exercise of the executive power of the Union, and the executive power of the Union shall extend to the giving of such directions to a State as may appear to the Government of India to be necessary for that purpose. (2) The executive power of the Union shall also extend to the giving of directions to a State as to the construction and maintenance of means of communication declared in the direction to be of national or military importance: Provided that", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "258", "t": "Power of the Union to confer powers, etc., on States in certain cases:(1) Notwithstanding anything in this Constitution, the President may, with the consent of the", "c": "Government of a State, entrust either conditionally or unconditionally to that Government or to its officers functions in relation to any matter to which the executive power of the Union extends. (2) A law made by Parliament which applies in any State may, notwithstanding that it relates to a matter with respect to which the Legislature of the State has no power to make laws, confer powers and impose duties, or authorise the conferring of powers and the imposition of duties, upon the State or officers and authorities thereof. (3) Where by virtu", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "259", "t": "The Bihar Consolidation of Holdings and Prevention of Fragmentation Act,", "c": "1956 (Bihar Act 22 of 1956).", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "260", "t": "Jurisdiction of the Union in relation to territories outside India", "c": "The Government of India may by agreement with the Government of any territory not being part of the territory of India undertake any executive, legislative or judicial functions vested in the Government of such territory, but every such agreement shall be subject to, and governed by, any law relating to the exercise of foreign jurisdiction for the time being in force.", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "261", "t": "Public acts, records and judicial proceedings", "c": "(1) Full faith and credit shall be given throughout the territory of India to public acts, records and judicial proceedings of the Union and of every State. (2) The manner in which and the conditions under which the acts, records and proceedings referred to in clause (1) shall be proved and the effect thereof determined shall be as provided by law made by Parliament. (3) Final judgments or orders delivered or passed by civil courts in any part of the territory of India shall be capable of execution anywhere within that territory according to la", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "262", "t": "Adjudication of disputes relating to waters of inter-State rivers or river valleys:(1) Parliament may by law provide for the adjudication of any dispute or complaint with", "c": "respect to the use, distribution or control of the waters of, or in, any inter-State river or river valley. (2) Notwithstanding anything in this Constitution, Parliament may by law provide that neither the Supreme Court nor any other court shall exercise jurisdiction in respect of any such dispute or complaint as is referred to in clause (1). Co-ordination between States", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "263", "t": "Provisions with respect to an inter-State Council", "c": "If at any time it appears to the President that the public interests would be served by the establishment of a Council charged with the duty of— (a) inquiring into and advising upon disputes which may have arisen between States; (b) investigating and discussing subjects in which some or all of the States, or the Union and one or more of the States, have a common interest; or (c) making recommendations upon any such subject and, in particular, recommendations for the better co-ordination of policy and action with respect to that subject, it shal", "p": "XI", "pn": "Union–State Relations", "clr": "#5C6BC0"}, {"n": "264", "t": "The Bihar Land Reforms (Fixation of Ceiling Area and Acquisition of Surplus", "c": "Land) (Amendment) Act, 1987 (Bihar Act 21 of 1987).", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "265", "t": "Taxes not to be imposed save by authority of law", "c": "No tax shall be levied or collected except by authority of law.", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "266", "t": "Consolidated Funds and public accounts of India and of the States", "c": "(1) Subject to the provisions of article 267 and to the provisions of this Chapter with respect to the assignment of the whole or part of the net proceeds of certain taxes and duties to States, all revenues received by the Government of India, all loans raised by that Government by the issue of treasury bills, loans or ways and means advances and all moneys received by that Government in repayment of loans shall form one consolidated fund to be entitled “the Consolidated Fund of India”, and all revenues received by the Government of a State, al", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "267", "t": "Contingency Fund", "c": "(1) Parliament may by law establish a Contingency Fund in the nature of an imprest to be entitled “the Contingency Fund of India” into which shall be paid from time to time such sums as may be determined by such law, and the said Fund shall be placed at the disposal of the President to enable advances to be made by him out of such Fund for the purposes of meeting unforeseen expenditure pending authorisation of such expenditure by Parliament by law under article 115 or article 116.", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "268", "t": "Duties levied by the Union but collected and appropriated by the States", "c": "(1) Such stamp duties 2[***] as are mentioned in the Union List shall be levied by the Government of India but shall be collected— (a) in the case where such duties are leviable within any 3[Union territory], by the Government of India, and (b) in other cases, by the States within which such duties are respectively leviable. (2) The proceeds in any financial year of any such duty leviable within any State shall not form part of the Consolidated Fund of India, but shall be assigned to that State. [268A. Service tax levied by Union and collected ", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "269", "t": "Taxes levied and collected by the Union but assigned to the States", "c": "1[(1) Taxes on the sale or purchase of goods and taxes on the consignment of goods 2[except as provided in article 269A] shall be levied and collected by the Government of India but shall be assigned and shall be deemed to have been assigned to the States on or after the 1st day of April, 1996 in the manner provided in clause (2). Explanation:- For the purposes of this clause,— (a) the expression “taxes on the sale or purchase of goods” shall mean taxes on sale or purchase of goods other than newspapers, where such sale or purchase takes place ", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "270", "t": "The Orissa Land Reforms (Amendment) Act, 1989 (Orissa Act 9 of 1990)", "c": "", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "271", "t": "Surcharge on certain duties and taxes for purposes of the Union", "c": "Notwithstanding anything in articles 269 and 270, Parliament may at any time increase any of the duties or taxes referred to in those articles 1[except the goods and services tax under article 246A,]by a surcharge for purposes of the Union and the whole proceeds of any such surcharge shall form part of the Consolidated Fund of India. 272. [Taxes which are levied and collected by the Union and may be distributed between the Union and the States.]:- Omitted by the Constitution (Eightieth Amendment) Act, 2000, Section 4 (w.e.f. 9.6.2000).", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "272", "t": "The Rajasthan Colonisation (Amendment) Act, 1987 (Rajasthan Act 2 of", "c": "1987).", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "273", "t": "Grants in lieu of export duty on jute and jute products", "c": "(1) There shall be charged on the Consolidated Fund of India in each year as grants-in-aid of the revenues of the States of Assam, Bihar, 2[Odisha] and West Bengal, in lieu of assignment of any share of the net proceeds in each year of export duty on jute and jute products to those States, such sums as may be prescribed.", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "274", "t": "Prior recommendation of President required to Bills affecting taxation in which", "c": "States are interested:- (1) No Bill or amendment which imposes or varies any tax or duty in which States are interested, or which varies the meaning of the expression “agricultural income” as defined for the purposes of the enactments relating to Indian income-tax, or which affects the principles on which under any of the foregoing provisions of this Chapter moneys are or may be distributable to States, or which imposes any such surcharge for the purposes of the Union as is mentioned in the foregoing provisions of this Chapter, shall be introdu", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "275", "t": "Grants from the Union to certain States", "c": "(1) Such sums as Parliament may by law provide shall be charged on the Consolidated Fund of India in each year as grants-in-aid of the revenues of such States as Parliament may determine to be in need of assistance, and different sums may be fixed for different States: Provided that there shall be paid out of the Consolidated Fund of India as grants-in-aid of the revenues of a State such capital and recurring sums as may be necessary to enable that State to meet the costs of such schemes of development as may be undertaken by the State with the", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "276", "t": "Taxes on professions, trades, callings and employments", "c": "(1) Notwithstanding anything in article 246, no law of the Legislature of a State relating to taxes for the benefit of the State or of a municipality, district board, local board or other local authority therein in respect of professions, trades, callings or employments shall be invalid on the ground that it relates to a tax on income. (2) The total amount payable in respect of any one person to the State or to any one municipality, district board, local board or other local authority in the State by way of taxes on professions, trades, calling", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "277", "t": "Savings", "c": "Any taxes, duties, cesses or fees which, immediately before the commencement of this Constitution, were being lawfully levied by the Government of any State or by any municipality or other local authority or body for the purposes of the State, municipality, district or other local area may, notwithstanding that those taxes, duties, cesses or fees are mentioned in the Union List, continue to be levied and to be applied to the same purposes until provision to the contrary is made by Parliament by law. 278. [Agreement with States in Part B of the ", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "278", "t": "The West Bengal Land Reforms (Amendment) Act, 1981 (West Bengal Act 50", "c": "of 1981).", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "279", "t": "Calculation of “net proceeds”, etc", "c": "(1) In the foregoing provisions of this Chapter, “net proceeds” means in relation to any tax or duty the proceeds thereof reduced by the cost of collection, and for the purposes of those provisions the net proceeds of any tax or duty, or of any part of any tax or duty, in or attributable to any area shall be ascertained and certified by the Comptroller and Auditor-General of India, whose certificate shall be final.", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "280", "t": "Finance Commission", "c": "(1) The President shall, within two years from the commencement of this Constitution and thereafter at the expiration of every fifth year or at such earlier time as the President considers necessary, by order constitute a Finance Commission which shall consist of a Chairman and four other members to be appointed by the President. (2) Parliament may by law determine the qualifications which shall be requisite for appointment as members of the Commission and the manner in which they shall be selected. (3) It shall be the duty of the Commission to", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "281", "t": "Recommendations of the Finance Commission", "c": "The President shall cause every recommendation made by the Finance Commission under the provisions of this Constitution together with an explanatory memorandum as to the action taken thereon to be laid before each House of Parliament. Miscellaneous Financial Provisions", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "282", "t": "Expenditure defrayable by the Union or a State out of its revenues", "c": "The Union or a State may make any grants for any public purpose, notwithstanding that the purpose is not one with respect to which Parliament or the Legislature of the State, as the case may be, may make laws.", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "283", "t": "Custody, etc., of Consolidated Funds, Contingency Funds and moneys credited to", "c": "the public accounts:- (1) The custody of the Consolidated Fund of India and the Contingency Fund of India, the payment of moneys into such Funds, the withdrawal of moneys therefrom, the custody of public moneys other than those credited to such Funds received by or on behalf of the Government of India, their payment into the public account of India and the withdrawal of moneys from such account and all other matters connected with or ancillary to matters aforesaid shall be regulated by law made by Parliament, and, until provision in that behalf", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "284", "t": "Custody of suitors’ deposits and other moneys received by public servants and", "c": "courts:- All moneys received by or deposited with— (a) any officer employed in connection with the affairs of the Union or of a State in his capacity as such, other than revenues or public moneys raised or received by the Government of India or the Government of the State, as the case may be, or (b) any court within the territory of India to the credit of any cause, matter, account or persons, shall be paid into the public account of India or the public account of State, as the case may be.", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "285", "t": "Exemption of property of the Union from State taxation", "c": "(1) The property of the Union shall, save in so far as Parliament may by law otherwise provide, be exempt from all taxes imposed by a State or by any authority within a State. (2) Nothing in clause (1) shall, until Parliament by law otherwise provides, prevent any authority within a State from levying any tax on any property of the Union to which such property was immediately before the commencement of this Constitution liable or treated as liable, so long as that tax continues to be levied in that State.", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "286", "t": "Restrictions as to imposition of tax on the sale or purchase of goods", "c": "(1) No law of a State shall impose, or authorise the imposition of, a tax on 1[the supply of goods or of services or both, where such supply takes place]— (a) outside the State; or (b) in the course of the import of the 2[goods or services or both] into, or export of the [goods or services or both]out of, the territory of India. [* * * *] [(2) Parliament may by law formulate principles for determining when a 5[supply of goods or of services or both] in any of the ways mentioned in clause (1).] [(3) * * * *]", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "287", "t": "Exemption from taxes on electricity", "c": "Save in so far as Parliament may by law otherwise provide, no law of a State shall impose, or authorise the imposition of, a tax on the consumption or sale of electricity (whether produced by a Government or other persons) which is— (a) consumed by the Government of India, or sold to the Government of India for consumption by that Government; or", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "288", "t": "Exemption from taxation by States in respect of water or electricity in certain", "c": "cases:- (1) Save in so far as the President may by order otherwise provide, no law of a State in force immediately before the commencement of this Constitution shall impose, or authorise the imposition of, a tax in respect of any water or electricity stored, generated, consumed, distributed or sold by any authority established by any existing law or any law made by Parliament for regulating or developing any inter-State river or river-valley. Explanation:- The expression “law of a State in force” in this clause shall include a law of a State pa", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "289", "t": "Exemption of property and income of a State from Union taxation", "c": "(1) The property and income of a State shall be exempt from Union taxation. (2) Nothing in clause (1) shall prevent the Union from imposing, or authorising the imposition of, any tax to such extent, if any, as Parliament may by law provide in respect of a trade or business of any kind carried on by, or on behalf of, the Government of a State, or any operations connected therewith, or any property used or occupied for the purposes of such trade or business, or any income accruing or arising in connection therewith. (3) Nothing in clause (2) shal", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "290", "t": "Adjustment in respect of certain expenses and pensions", "c": "Where under the provisions of this Constitution the expenses of any court or Commission, or the pension payable to or in respect of a person who has served before the commencement of this Constitution under the Crown in India or after such commencement in connection with the affairs of the Union or of a State, are charged on the Consolidated Fund of India or the Consolidated Fund of a State, then, if— (a) in the case of a charge on the Consolidated Fund of India, the court or Commission serves any of the separate needs of a State, or the person", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "292", "t": "Borrowing by the Government of India", "c": "The executive power of the Union extends to borrowing upon the security of the Consolidated Fund of India within such limits, if any, as may from time to time be fixed by Parliament by law and to the giving of guarantees within such limits, if any, as may be so fixed.", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "293", "t": "Borrowing by States", "c": "(1) Subject to the provisions of this article, the executive power of a State extends to borrowing within the territory of India upon the security of the Consolidated Fund of the State within such limits, if any, as may from time to time be fixed by the Legislature of such State by law and to the giving of guarantees within such limits, if any, as may be so fixed. (2) The Government of India may, subject to such conditions as may be laid down by or under any law made by Parliament, make loans to any State or, so long as any limits fixed under a", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "294", "t": "Succession to property, assets, rights, liabilities and obligations in certain cases:As from the commencement of this Constitution—", "c": "(a) all property and assets which immediately before such commencement were vested in His Majesty for the purposes of the Government of the Dominion of India and all property and assets which immediately before such commencement were vested in His Majesty for the purposes of the Government of each Governor‘s Province shall vest respectively in the Union and the corresponding State, and (b) all rights, liabilities and obligations of the Government of the Dominion of India and of the Government of each Governor's Province, whether arising out of ", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "295", "t": "Succession to property, assets, rights, liabilities and obligations in other cases:(1) As from the commencement of this Constitution—", "c": "(a) all property and assets which immediately before such commencement were vested in any Indian State corresponding to a State specified in Part B of the First Schedule shall vest in the Union, if the purposes for which such property and assets were held immediately before such commencement will thereafter be purposes of the Union relating to any of the matters enumerated in the Union List, and THE CONSTITUTION OF INDIA (Part XII. - Finance, Property, Contracts And Suits) (b) all rights, liabilities and obligations of the Government of any Ind", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "296", "t": "Property accruing by escheat or lapse or as bona vacantia", "c": "Subject as hereinafter provided, any property in the territory of India which, if this Constitution had not come into operation, would have accrued to His Majesty or, as the case may be, to the Ruler of an Indian State by escheat or lapse, or as bona vacantia for want of a rightful owner, shall, if it is property situate in a State, vest in such State, and shall, in any other case, vest in the Union: Provided that any property which at the date when it would have so accrued to His Majesty or to the Ruler of an Indian State was in the possession", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "299", "t": "Contracts", "c": "(1) All contracts made in the exercise of the executive power of the Union or of a State shall be expressed to be made by the President, or by the Governor 3[***] of the State, as the case may be, and all such contracts and all assurances of property made in the exercise of that power shall be executed on behalf of the President or the Governor 3[***] by such persons and in such manner as he may direct or authorise.", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "300", "t": "Suits and proceedings", "c": "(1) The Government of India may sue or be sued by the name of the Union of India and the Government of a State may sue or be sued by the name of the State and may, subject to any provisions which may be made by Act of Parliament or of the Legislature of such State enacted by virtue of powers conferred by this Constitution, sue or be sued in relation to their respective affairs in the like cases as the Dominion of India and the corresponding Provinces or the corresponding Indian States might have sued or been sued if this Constitution had not be", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "300A", "t": "Persons not to be deprived of property save by authority of law", "c": "No person shall be deprived of his property save by authority of law.", "p": "XII", "pn": "Finance & Property", "clr": "#FFB300"}, {"n": "301", "t": "Freedom of trade, commerce and intercourse", "c": "Subject to the other provisions of this Part, trade, commerce and intercourse throughout the territory of India shall be free.", "p": "XIII", "pn": "Trade & Commerce", "clr": "#EC407A"}, {"n": "302", "t": "Power of Parliament to impose restrictions on trade, commerce and intercourse:Parliament may by law impose such restrictions on the freedom of trade, commerce or", "c": "intercourse between one State and another or within any part of the territory of India as may be required in the public interest.", "p": "XIII", "pn": "Trade & Commerce", "clr": "#EC407A"}, {"n": "303", "t": "Restrictions on the legislative powers of the Union and of the States with regard to", "c": "trade and commerce:- (1) Notwithstanding anything in article 302, neither Parliament nor the Legislature of a State shall have power to make any law giving, or authorising the giving of, any preference to one State over another, or making, or authorising the making of, any discrimination between one State and another, by virtue of any entry relating to trade and commerce in any of the Lists in the Seventh Schedule. (2) Nothing in clause (1) shall prevent Parliament from making any law giving, or authorising the giving of, any preference or maki", "p": "XIII", "pn": "Trade & Commerce", "clr": "#EC407A"}, {"n": "304", "t": "Restrictions on trade, commerce and intercourse among States", "c": "Notwithstanding anything in article 301 or article 303, the Legislature of a State may by law— (a) impose on goods imported from other States 1[or the Union territories] any tax to which similar goods manufactured or produced in that State are subject, so, however, as not to discriminate between goods so imported and goods so manufactured or produced; and (b) impose such reasonable restrictions on the freedom of trade, commerce or intercourse with or within that State as may be required in the public interest: Provided that no Bill or amendment", "p": "XIII", "pn": "Trade & Commerce", "clr": "#EC407A"}, {"n": "307", "t": "Appointment of authority for carrying out the purposes of articles 301 to 304:Parliament may by law appoint such authority as it considers appropriate for carrying out the", "c": "purposes of articles 301, 302, 303 and 304, and confer on the authority so appointed such powers and such duties as it thinks necessary.", "p": "XIII", "pn": "Trade & Commerce", "clr": "#EC407A"}, {"n": "308", "t": "Interpretation", "c": "In this Part, unless the context otherwise requires, the expression “State” 1[does not include the State of Jammu and Kashmir.]", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "309", "t": "Recruitment and conditions of service of persons serving the Union or a State:Subject to the provisions of this Constitution, Acts of the appropriate Legislature may", "c": "regulate the recruitment, and conditions of service of persons appointed, to public services and posts in connection with the affairs of the Union or of any State: Provided that it shall be competent for the President or such person as he may direct in the case of services and posts in connection with the affairs of the Union, and for the Governor 2[***] of a State or such person as he may direct in the case of services and posts in connection with the affairs of the State, to make rules regulating the recruitment, and the conditions of service", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "310", "t": "Tenure of office of persons serving the Union or a State", "c": "(1) Except as expressly provided by this Constitution, every person who is a member of a defence service or of a civil service of the Union or of an all-India service or holds any post connected with defence or any civil post under the Union holds office during the pleasure of the President, and every person who is a member of a civil service of a State or holds any civil post under a State holds office during the pleasure of the Governor 3[***] of the State.", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "311", "t": "Dismissal, removal or reduction in rank of persons employed in civil capacities", "c": "under the Union or a State:- (1) No person who is a member of a civil service of the Union or an all-India service or a civil service of a State or holds a civil post under the Union or a State shall be dismissed or removed by an authority subordinate to that by which he was appointed. [(2) No such person as aforesaid shall be dismissed or removed or reduced in rank except after an inquiry in which he has been informed of the charges against him and given a reasonable opportunity of being heard in respect of those charges 4[***]: [Provided that", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "312", "t": "All-India services", "c": "(1) Notwithstanding anything in 1[Chapter VI of Part VI or Part XI], if the Council of States has declared by resolution supported by not less than two-thirds of the members present and voting that it is necessary or expedient in the national interest so to do, Parliament may by law provide for the creation of one or more all India services [(including an all-India judicial service)] common to the Union and the States, and, subject to the other provisions of this Chapter, regulate the recruitment, and the conditions of service of persons appoin", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "313", "t": "Transitional provisions", "c": "Until other provision is made in this behalf under this Constitution, all the laws in force immediately before the commencement of this Constitution and applicable to any public service or any post which continues to exist after the commencement of this Constitution, as an all-India service or as service or post under the Union or a State shall continue in force so far as consistent with the provisions of this Constitution. 314. [Provision for protection of existing officers of certain services.]:- Omitted by the Constitution (Twenty-eighth Ame", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "315", "t": "Public Service Commissions for the Union and for the States", "c": "(1) Subject to the provisions of this article, there shall be a Public Service Commission for the Union and a Public Service Commission for each State. (2) Two or more States may agree that there shall be one Public Service Commission for that group of States, and if a resolution to that effect is passed by the House or, where there are two Houses, by each House of the Legislature of each of those States, Parliament may by law provide for the appointment of a Joint State Public Service Commission (referred to in this Chapter as Joint Commission", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "316", "t": "Appointment and term of office of members", "c": "(1) The Chairman and other members of a Public Service Commission shall be appointed, in the case of the Union Commission or a Joint Commission, by the President, and in the case of a State Commission, by the Governor of the State: Provided that as nearly as may be one-half of the members of every Public Service Commission shall be persons who at the dates of their respective appointments have held office for at least ten years either under the Government of India or under the Government of a State, and in computing the said period of ten years", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "317", "t": "Removal and suspension of a member of a Public Service Commission:(1) Subject to the provisions of clause (3), the Chairman or any other member of a Public", "c": "Service Commission shall only be removed from his office by order of the President on the ground of misbehaviour after the Supreme Court, on reference being made to it by the President, has, on inquiry held in accordance with the procedure prescribed in that behalf under article 145, reported that the Chairman or such other member, as the case may be, ought on any such ground to be removed. (2) The President, in the case of the Union Commission or a Joint Commission, and the Governor 2[***] in the case of a State Commission, may suspend from of", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "318", "t": "Power to make regulations as to conditions of service of members and staff of the", "c": "Commission:- In the case of the Union Commission or a Joint Commission, the President and, in the case of a State Commission, the Governor 1[***] of the State may by regulations— (a) determine the number of members of the Commission and their conditions of service; and (b) make provision with respect to the number of members of the staff of the Commission and their conditions of service: Provided that the conditions of service of a member of a Public Service Commission shall not be varied to his disadvantage after his appointment.", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "319", "t": "Prohibition as to the holding of offices by members of Commission on ceasing to", "c": "be such members:- On ceasing to hold office— (a) the Chairman of the Union Public Service Commission shall be ineligible for further employment either under the Government of India or under the Government of a State;", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "320", "t": "Functions of Public Service Commissions", "c": "(1) It shall be the duty of the Union and the State Public Service Commissions to conduct examinations for appointments to the services of the Union and the services of the State respectively. (2) It shall also be the duty of the Union Public Service Commission, if requested by any two or more States so to do, to assist those States in framing and operating schemes of joint recruitment for any services for which candidates possessing special qualifications are required. (3) The Union Public Service Commission or the State Public Service Commiss", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "321", "t": "Power to extend functions of Public Service Commissions", "c": "An Act made by Parliament or, as the case may be, the Legislature of a State may provide for the exercise of additional functions by the Union Public Service Commission or the State Public Service Commission as respects the services of the Union or the State and also as respects the services of any local authority or other body corporate constituted by law or of any public institution.", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "322", "t": "Expenses of Public Service Commissions", "c": "The expenses of the Union or a State Public Service Commission, including any salaries, allowances and pensions payable to or in respect of the members or staff of the Commission, shall be charged on the Consolidated Fund of India or, as the case may be, the Consolidated Fund of the State.", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "323", "t": "Reports of Public Service Commissions", "c": "(1) It shall be the duty of the Union Commission to present annually to the President a report as to the work done by the Commission and on receipt of such report the President shall cause a copy thereof together with a memorandum explaining, as respects the cases, if any, where the advice of the Commission was not accepted, the reasons for such non-acceptance to be laid before each House of Parliament. (2) It shall be the duty of a State Commission to present annually to the Governor [***] of the State a report as to the work done by the Commi", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "323A", "t": "Administrative tribunals", "c": "(1) Parliament may, by law, provide for the adjudication or trial by administrative tribunals of disputes and complaints with respect to recruitment and conditions of service of persons appointed to public services and posts in connection with the affairs of the Union or of any State or of any local or other authority within the territory of India or under the control of the Government of India or of any corporation owned or controlled by the Government. (2) A law made under clause (1) may— (a) provide for the establishment of an administrative", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "323B", "t": "Tribunals for other matters", "c": "(1) The appropriate Legislature may, by law, provide for the adjudication or trial by tribunals of any disputes, complaints, or offences with respect to all or any of the matters specified in clause (2) with respect to which such Legislature has power to make laws. (2) The matters referred to in clause (1) are the following, namely:— (a) levy, assessment, collection and enforcement of any tax; (b) foreign exchange, import and export across customs frontiers; (c) industrial and labour disputes; (d) land reforms by way of acquisition by the State", "p": "XIV", "pn": "Services", "clr": "#26A69A"}, {"n": "324", "t": "Superintendence, direction and control of elections to be vested in an Election", "c": "Commission:- (1) The superintendence, direction and control of the preparation of the electoral rolls for, and the conduct of, all elections to Parliament and to the Legislature of every State and of elections to the offices of President and Vice-President held under this Constitution 1[***] shall be vested in a Commission (referred to in this Constitution as the Election Commission). (2) The Election Commission shall consist of the Chief Election Commissioner and such number of other Election Commissioners, if any, as the President may from ti", "p": "XV", "pn": "Elections", "clr": "#EF5350"}, {"n": "325", "t": "No person to be ineligible for inclusion in, or to claim to be included in a special,", "c": "electoral roll on grounds of religion, race, caste or sex:- There shall be one general electoral roll for every territorial constituency for election to either House of Parliament or to the House or either House of the Legislature of a State and no person shall be ineligible for inclusion in any such roll or claim to be included in any special electoral roll for any such constituency on grounds only of religion, race, caste, sex or any of them.", "p": "XV", "pn": "Elections", "clr": "#EF5350"}, {"n": "326", "t": "Elections to the House of the People and to the Legislative Assemblies of States to", "c": "be on the basis of adult suffrage:- The elections to the House of the People and to the Legislative Assembly of every State shall be on the basis of adult suffrage; that is to say, every person who is a citizen of India and who is not less than 2[eighteen years] of age on such date as may be fixed in that behalf by or under any law made by the appropriate Legislature and is not otherwise disqualified under this Constitution or any law made by the appropriate Legislature on the ground of non-residence, unsoundness of mind, crime or corrupt or il", "p": "XV", "pn": "Elections", "clr": "#EF5350"}, {"n": "327", "t": "Power of Parliament to make provision with respect to elections to Legislatures:Subject to the provisions of this Constitution, Parliament may from time to time by law", "c": "make provision with respect to all matters relating to, or in connection with, elections to either House of Parliament or to the House or either House of the Legislature of a State including the preparation of electoral rolls, the delimitation of constituencies and all other matters necessary for securing the due constitution of such House or Houses.", "p": "XV", "pn": "Elections", "clr": "#EF5350"}, {"n": "328", "t": "Power of Legislature of a State to make provision with respect to elections to such", "c": "Legislature:- Subject to the provisions of this Constitution and in so far as provision in that behalf is not made by Parliament, the Legislature of a State may from time to time by law make provision with respect to all matters relating to, or in connection with, the elections to the House or either House of the Legislature of the State including the preparation of electoral rolls and all other matters necessary for securing the due constitution of such House or Houses.", "p": "XV", "pn": "Elections", "clr": "#EF5350"}, {"n": "329", "t": "Bar to interference by courts in electoral matters", "c": "1[Notwithstanding anything in this Constitution 2***—] (a) the validity of any law relating to the delimitation of constituencies or the allotment of seats to such constituencies, made or purporting to be made under article 327 or article 328, shall not be called in question in any court; (b) no election to either House of Parliament or to the House or either House of the Legislature of a State shall be called in question except by an election petition presented to such authority and in such manner as may be provided for by or under any law mad", "p": "XV", "pn": "Elections", "clr": "#EF5350"}, {"n": "330", "t": "Reservation of seats for Scheduled Castes and Scheduled Tribes in the House of", "c": "the People:(1) Seats shall be reserved in the House of the People for — (a) the Scheduled Castes; [(b) the Scheduled Tribes except the Scheduled Tribes in the autonomous districts of Assam; and] (c) the Scheduled Tribes in the autonomous districts of Assam. (2) The number of seats reserved in any State 2[or Union territory] for the Scheduled Castes or the Scheduled Tribes under clause (1) shall bear, as nearly as may be, the same proportion to the total number of seats allotted to that State 2[or Union territory] in the House of the People as t", "p": "XVI", "pn": "Special Provisions", "clr": "#FF7043"}, {"n": "331", "t": "Representation of the Anglo-Indian Community in the House of the People.—", "c": "Notwithstanding anything in article 81, the President may, if he is of opinion that the AngloIndian community is not adequately represented in the House of the People, nominate not more than two members of that community to the House of the People.", "p": "XVI", "pn": "Special Provisions", "clr": "#FF7043"}, {"n": "332", "t": "Reservation of seats for Scheduled Castes and Scheduled Tribes in the Legislative", "c": "Assemblies of the States:- (1) Seats shall be reserved for the Scheduled Castes and the Scheduled Tribes, 2[except the Scheduled Tribes in the autonomous districts of Assam], in the Legislative Assembly of every every State 3[***]. (2) Seats shall be reserved also for the autonomous districts in the Legislative Assembly of the State of Assam. (3) The number of seats reserved for the Scheduled Castes or the Scheduled Tribes in the Legislative Assembly of any State under clause (1) shall bear, as nearly as may be, the same proportion to the total", "p": "XVI", "pn": "Special Provisions", "clr": "#FF7043"}, {"n": "333", "t": "Representation of the Anglo-Indian community in the Legislative Assemblies of", "c": "the States:- Notwithstanding anything in article 170, the Governor 2[***] of a State may, if he is of opinion that the Anglo- Indian community needs representation in the Legislative Assembly of the State and is not adequately represented therein, 3[nominate one member of that community to the Assembly]. 334. 4[Reservation of seats and special representation to cease after certain period]:Notwithstanding anything in the foregoing provisions of this Part, the provisions of this Constitution relating to— (a) the reservation of seats for the Sched", "p": "XVI", "pn": "Special Provisions", "clr": "#FF7043"}, {"n": "335", "t": "Claims of Scheduled Castes and Scheduled Tribes to services and posts", "c": "The claims of the members of the Scheduled Castes and the Scheduled Tribes shall be taken into consideration, consistently with the maintenance of efficiency of administration, in the making of appointments to services and posts in connection with the affairs of the Union or of a State: [Provided that nothing in this article shall prevent in making of any provision in favour of the members of the Scheduled Castes and the Scheduled Tribes for relaxation in qualifying marks in any examination or lowering the standards of evaluation, for reservati", "p": "XVI", "pn": "Special Provisions", "clr": "#FF7043"}, {"n": "336", "t": "Special provision for Anglo-Indian community in certain services", "c": "(1) During the first two years after the commencement of this Constitution, appointments of members of the Anglo-Indian community to posts in the railway, customs, postal and telegraph services of the Union shall be made on the same basis as immediately before the fifteenth day of August, 1947. During every succeeding period of two years, the number of posts reserved for the members of the said community in the said services shall, as nearly as possible, be less by ten per cent. than the numbers so reserved during the immediately preceding peri", "p": "XVI", "pn": "Special Provisions", "clr": "#FF7043"}, {"n": "337", "t": "Special provision with respect to educational grants for the benefit of AngloIndian community", "c": "During the first three financial years after the commencement of this Constitution, the same grants, if any, shall be made by the Union and by each State 1*** for the benefit of the Anglo-Indian community in respect of education as were made in the financial year ending on the thirty-first day of March, 1948. During every succeeding period of three years the grants may be less by ten per cent. than those for the immediately preceding period of three years: Provided that at the end of ten years from the commencement of this Constitution such gra", "p": "XVI", "pn": "Special Provisions", "clr": "#FF7043"}, {"n": "339", "t": "Control of the Union over the administration of Scheduled Areas and the welfare", "c": "of Scheduled Tribes:- (1) The President may at any time and shall, at the expiration of ten years from the commencement of this Constitution by order appoint a Commission to report on the administration of the Scheduled Areas and the welfare of the Scheduled Tribes in the States 2[***]. The order may define the composition, powers and procedure of the Commission and may contain such incidental or ancillary provisions as the President may consider necessary or desirable. (2) The executive power of the Union shall extend to the giving of directio", "p": "XVI", "pn": "Special Provisions", "clr": "#FF7043"}, {"n": "340", "t": "Appointment of a Commission to investigate the conditions of backward classes:(1) The President may by order appoint a Commission consisting of such persons as he", "c": "thinks fit to investigate the conditions of socially and educationally backward classes within the territory of India and the difficulties under which they labour and to make recommendations as to the steps that should be taken by the Union or any State to remove such difficulties and to improve their condition and as to the grants that should be made for the purpose by the Union or any State and the conditions subject to which such grants should be made, and the order appointing such Commission shall define the procedure to be followed by the ", "p": "XVI", "pn": "Special Provisions", "clr": "#FF7043"}, {"n": "341", "t": "Scheduled Castes", "c": "(1) The President 1[may with respect to any State 2[or Union territory], and where it is a State 3[***], after consultation with the Governor 4[*** thereof,] by public notification5, specify the castes, races or tribes or parts of or groups within castes, races or tribes which shall for the purposes of this Constitution be deemed to be Scheduled Castes in relation to that State 6[or Union territory, as the case may be.] (2) Parliament may by law include in or exclude from the list of Scheduled Castes specified in a notification issued under cla", "p": "XVI", "pn": "Special Provisions", "clr": "#FF7043"}, {"n": "342", "t": "Scheduled Tribes", "c": "(1) The President 7[may with respect to any State or Union territory, and where it is a State 3[***], after consultation with the Governor 4[*** thereof,] by public notification8, specify the tribes or tribal communities or parts of or groups within tribes or tribal communities which shall for the purposes of this Constitution be deemed to be Scheduled Tribes in relation to that State or Union territory, as the case may be.", "p": "XVI", "pn": "Special Provisions", "clr": "#FF7043"}, {"n": "343", "t": "Official language of the Union", "c": "(1) The official language of the Union shall be Hindi in Devanagari script. The form of numerals to be used for the official purposes of the Union shall be the international form of Indian numerals. (2) Notwithstanding anything in clause (1), for a period of fifteen years from the commencement of this Constitution, the English language shall continue to be used for all the official purposes of the Union for which it was being used immediately before such commencement: Provided that the President may, during the said period, by order1 authorise ", "p": "XVII", "pn": "Official Language", "clr": "#29B6F6"}, {"n": "344", "t": "Commission and Committee of Parliament on official language", "c": "(1) The President shall, at the expiration of five years from the commencement of this Constitution and thereafter at the expiration of ten years from such commencement, by order constitute a Commission which shall consist of a Chairman and such other members representing the different languages specified in the Eighth Schedule as the President may appoint, and the order shall define the procedure to be followed by the Commission. (2) It shall be the duty of the Commission to make recommendations to the President as to— (a) the progressive use ", "p": "XVII", "pn": "Official Language", "clr": "#29B6F6"}, {"n": "345", "t": "Official language or languages of a State", "c": "Subject to the provisions of articles 346 and 347, the Legislature of a State may by law adopt any one or more of the languages in use in the State or Hindi as the language or languages to be used for all or any of the official purposes of that State: THE CONSTITUTION OF INDIA (Part XVII. - Official Language) Provided that, until the Legislature of the State otherwise provides by law, the English language shall continue to be used for those official purposes within the State for which it was being used immediately before the commencement of thi", "p": "XVII", "pn": "Official Language", "clr": "#29B6F6"}, {"n": "346", "t": "Official language for communication between one State and another or between a", "c": "State and the Union:- The language for the time being authorised for use in the Union for official purposes shall be the official language for communication between one State and another State and between a State and the Union: Provided that if two or more States agree that the Hindi language should be the official language for communication between such States, that language may be used for such communication.", "p": "XVII", "pn": "Official Language", "clr": "#29B6F6"}, {"n": "347", "t": "Special provision relating to language spoken by a section of the population of a", "c": "State:- On a demand being made in that behalf the President may, if he is satisfied that a substantial proportion of the population of a State desire the use of any language spoken by them to be recognised by that State, direct that such language shall also be officially recognised throughout that State or any part thereof for such purpose as he may specify. CHAPTER - III. LANGUAGE OF THE SUPREME COURT, HIGH COURTS, ETC.", "p": "XVII", "pn": "Official Language", "clr": "#29B6F6"}, {"n": "348", "t": "Language to be used in the Supreme Court and in the High Courts and for Acts,", "c": "Bills, etc.:- (1) Notwithstanding anything in the foregoing provisions of this Part, until Parliament by law otherwise provides— (a) all proceedings in the Supreme Court and in every High Court, (b) the authoritative texts— (i) of all Bills to be introduced or amendments thereto to be moved in either House of Parliament or in the House or either House of the Legislature of a State, (ii) of all Acts passed by Parliament or the Legislature of a State and of all Ordinances promulgated by the President or the Governor 1[***] of a State, and", "p": "XVII", "pn": "Official Language", "clr": "#29B6F6"}, {"n": "349", "t": "Special procedure for enactment of certain laws relating to language.— During the", "c": "period of fifteen years from the commencement of this Constitution, no Bill or amendment making provision for the language to be used for any of the purposes mentioned in clause (1) of article 348 shall be introduced or moved in either House of Parliament without the previous sanction of the President, and the President shall not give his sanction to the introduction of any such Bill or the moving of any such amendment except after he has taken into consideration the recommendations of the Commission constituted under clause (1) of article 344 ", "p": "XVII", "pn": "Official Language", "clr": "#29B6F6"}, {"n": "350", "t": "Language to be used in representations for redress of grievances", "c": "Every person shall be entitled to submit a representation for the redress of any grievance to any officer or authority of the Union or a State in any of the languages used in the Union or in the State, as the case may be.", "p": "XVII", "pn": "Official Language", "clr": "#29B6F6"}, {"n": "350B", "t": "Special Officer for linguistic minorities", "c": "(1) There shall be a Special Officer for linguistic minorities to be appointed by the President. (2) It shall be the duty of the Special Officer to investigate all matters relating to the safeguards provided for linguistic minorities under this Constitution and report to the President upon those matters at such intervals as the President may direct, and the President shall cause all such reports to be laid before each House of Parliament, and sent to the Governments of the States concerned.]", "p": "XVII", "pn": "Official Language", "clr": "#29B6F6"}, {"n": "351", "t": "Directive for development of the Hindi language", "c": "It shall be the duty of the Union to promote the spread of the Hindi language, to develop it so that it may serve as a medium of expression for all the elements of the composite culture of India and to secure its enrichment by assimilating without interfering with its genius, the forms, style and expressions used in Hindustani and in the other languages of India specified in the Eighth Schedule, and by drawing, wherever necessary or desirable, for its vocabulary, primarily on Sanskrit and secondarily on other languages.", "p": "XVII", "pn": "Official Language", "clr": "#29B6F6"}, {"n": "352", "t": "Proclamation of Emergency", "c": "(1) If the President is satisfied that a grave emergency exists whereby the security of India or of any part of the territory thereof is threatened, whether by war or external aggression or 1[armed rebellion], he may, by Proclamation, make a declaration to that effect 2[in respect of the whole of India or of such part of the territory thereof as may be specified in the Proclamation]. [Explanation:- A Proclamation of Emergency declaring that the security of India or any part of the territory thereof is threatened by war or by external aggression", "p": "XVIII", "pn": "Emergency Provisions", "clr": "#EF9A9A"}, {"n": "353", "t": "Effect of Proclamation of Emergency", "c": "While a Proclamation of Emergency is in operation, then— (a) notwithstanding anything in this Constitution, the executive power of the Union shall extend to the giving of directions to any State as to the manner in which the executive power thereof is to be exercised; (b) the power of Parliament to make laws with respect to any matter shall include power to make laws conferring powers and imposing duties, or authorising the conferring of powers and the imposition of duties, upon the Union or officers and authorities of the Union as respects tha", "p": "XVIII", "pn": "Emergency Provisions", "clr": "#EF9A9A"}, {"n": "354", "t": "Application of provisions relating to distribution of revenues while a Proclamation", "c": "of Emergency is in operation:- (1) The President may, while a Proclamation of Emergency is in operation, by order direct that all or any of the provisions of articles 268 to 279 shall for such period, not extending in any case beyond the expiration of the financial year in which such Proclamation ceases to operate, as may be specified in the order, have effect subject to such exceptions or modifications as he thinks fit. (2) Every order made under clause (1) shall, as soon as may be after it is made, be laid before each House of Parliament.", "p": "XVIII", "pn": "Emergency Provisions", "clr": "#EF9A9A"}, {"n": "355", "t": "Duty of the Union to protect States against external aggression and internal", "c": "disturbance:- It shall be the duty of the Union to protect every State against external aggression and internal disturbance and to ensure that the Government of every State is carried on in accordance with the provisions of this Constitution.", "p": "XVIII", "pn": "Emergency Provisions", "clr": "#EF9A9A"}, {"n": "356", "t": "Provisions in case of failure of constitutional machinery in States", "c": "(1) If the President, on receipt of a report from the Governor 2[***] of a State or otherwise, is satisfied that a situation has arisen in which the Government of the State cannot be carried on in accordance with the provisions of this Constitution, the President may by Proclamation—", "p": "XVIII", "pn": "Emergency Provisions", "clr": "#EF9A9A"}, {"n": "357", "t": "Exercise of legislative powers under Proclamation issued under article 356:(1) Where by a Proclamation issued under clause (1) of article 356, it has been declared that", "c": "the powers of the Legislature of the State shall be exercisable by or under the authority of Parliament, it shall be competent— (a) for Parliament to confer on the President the power of the Legislature of the State to make laws, and to authorise the President to delegate, subject to such conditions as he may think fit to impose, the power so conferred to any other authority to be specified by him in that behalf; (b) for Parliament, or for the President or other authority in whom such power to make laws is vested under sub-clause (a), to make l", "p": "XVIII", "pn": "Emergency Provisions", "clr": "#EF9A9A"}, {"n": "358", "t": "Suspension of provisions of article 19 during emergencies", "c": "2[(1)] 3[While a Proclamation of Emergency declaring that the security of India or any part of the territory thereof is threatened by war or by external aggression is in operation], nothing in article 19 shall restrict the power of the State as defined in Part III to make any law or to take any executive action which the State would but for the provisions contained in that Part be competent to make or to take, but any law so made shall, to the extent of the incompetency, cease to have effect as soon as the Proclamation ceases to operate, except", "p": "XVIII", "pn": "Emergency Provisions", "clr": "#EF9A9A"}, {"n": "359", "t": "Suspension of the enforcement of the rights conferred by Part III during", "c": "emergencies:- (1) Where a Proclamation of Emergency is in operation, the President may by order declare that the right to move any court for the enforcement of such of 2[the rights conferred by Part III (except articles 20 and 21)] as may be mentioned in the order and all proceedings pending in any court for the enforcement of the rights so mentioned shall remain suspended for the period during which the Proclamation is in force or for such shorter period as may be specified in the order. [(1A) While an order made under clause (1) mentioning an", "p": "XVIII", "pn": "Emergency Provisions", "clr": "#EF9A9A"}, {"n": "360", "t": "Provisions as to financial emergency", "c": "(1) If the President is satisfied that a situation has arisen whereby the financial stability or credit of India or of any part of the territory thereof is threatened, he may by a Proclamation make a declaration to that effect. [(2) A Proclamation issued under clause (1)— (a) may be revoked or varied by a subsequent Proclamation; (b) shall be laid before each House of Parliament;", "p": "XVIII", "pn": "Emergency Provisions", "clr": "#EF9A9A"}, {"n": "361", "t": "Protection of President and Governors and Rajpramukhs", "c": "(1) The President, or the Governor or Rajpramukh of a State, shall not be answerable to any court for the exercise and performance of the powers and duties of his office or for any act done or purporting to be done by him in the exercise and performance of those powers and duties: Provided that the conduct of the President may be brought under review by any court, tribunal or body appointed or designated by either House of Parliament for the investigation of a charge under article 61: Provided further that nothing in this clause shall be constr", "p": "XIX", "pn": "Miscellaneous", "clr": "#A5D6A7"}, {"n": "363", "t": "Bar to interference by courts in disputes arising out of certain treaties,", "c": "agreements, etc.:- (1) Notwithstanding anything in this Constitution but subject to the provisions of article 143, neither the Supreme Court nor any other court shall have jurisdiction in any dispute arising out of any provision of a treaty, agreement, covenant, engagement, sanad or other similar instrument which was entered into or executed before the commencement of this Constitution by any Ruler of an Indian State and to which the Government of the Dominion of India or any of its predecessor Governments was a party and which has or has been ", "p": "XIX", "pn": "Miscellaneous", "clr": "#A5D6A7"}, {"n": "364", "t": "Special provisions as to major ports and aerodromes", "c": "(1) Notwithstanding anything in this Constitution, the President may by public notification direct that as from such date as may be specified in the notification— (a) any law made by Parliament or by the Legislature of a State shall not apply to any major port or aerodrome or shall apply thereto subject to such exceptions or modifications as may be specified in the notification, or (b) any existing law shall cease to have effect in any major port or aerodrome except as respects things done or omitted to be done before the said date, or shall in", "p": "XIX", "pn": "Miscellaneous", "clr": "#A5D6A7"}, {"n": "365", "t": "Effect of failure to comply with, or to give effect to, directions given by the Union:Where any State has failed to comply with, or to give effect to, any directions given in the", "c": "exercise of the executive power of the Union under any of the provisions of this Constitution, it shall be lawful for the President to hold that a situation has arisen in which the Government of the State cannot be carried on in accordance with the provisions of this Constitution.", "p": "XIX", "pn": "Miscellaneous", "clr": "#A5D6A7"}, {"n": "366", "t": "Definitions", "c": "In this Constitution, unless the context otherwise requires, the following expressions have the meanings hereby respectively assigned to them, that is to say— (1) “agricultural income” means agricultural income as defined for the purposes of the enactments relating to Indian income-tax; (2) “an Anglo-Indian” means a person whose father or any of whose other male progenitors in the male line is or was of European descent but who is domiciled within the territory of India and is or was born within such territory of parents habitually resident the", "p": "XIX", "pn": "Miscellaneous", "clr": "#A5D6A7"}, {"n": "367", "t": "Interpretation", "c": "(1) Unless the context otherwise requires, the General Clauses Act, 1897, shall, subject to any adaptations and modifications that may be made therein under article 372, apply for the interpretation of this Constitution as it applies for the interpretation of an Act of the Legislature of the Dominion of India. (2) Any reference in this Constitution to Acts or laws of, or made by, Parliament, or to Acts or laws of, or made by, the Legislature of a State 2[***], shall be construed as including a reference to an Ordinance made by the President or,", "p": "XIX", "pn": "Miscellaneous", "clr": "#A5D6A7"}, {"n": "369", "t": "Temporary power to Parliament to make laws with respect to certain matters in", "c": "the State List as if they were matters in the Concurrent List:- Notwithstanding anything in this Constitution, Parliament shall, during a period of five years from the commencement of this Constitution, have power to make laws with respect to the following matters as if they were enumerated in the Concurrent List, namely:— (a) trade and commerce within a State in, and the production, supply and distribution of, cotton and woollen textiles, raw cotton (including ginned cotton and unginned cotton or kapas), cotton seed, paper (including newsprint", "p": "XXI", "pn": "Transitional Provisions", "clr": "#80CBC4"}, {"n": "371E", "t": "Establishment of Central University in Andhra Pradesh", "c": "Parliament may by law provide for the establishment of a University in the State of Andhra Pradesh.] [371F. Special provisions with respect to the State of Sikkim:- Notwithstanding anything in this Constitution,— (a) the Legislative Assembly of the State of Sikkim shall consist of not less than thirty members; (b) as from the date of commencement of the Constitution (Thirty-sixth Amendment) Act, 1975 (hereafter in this article referred to as the appointed day)— (i) the Assembly for Sikkim formed as a result of the elections held in Sikkim in Ap", "p": "XXI", "pn": "Transitional Provisions", "clr": "#80CBC4"}, {"n": "372", "t": "Continuance in force of existing laws and their adaptation", "c": "(1) Notwithstanding the repeal by this Constitution of the enactments referred to in article 395 but subject to the other provisions of this Constitution, all the law in force in the territory of India immediately before the commencement of this Constitution shall continue in force therein until altered or repealed or amended by a competent Legislature or other competent authority. (2) For the purpose of bringing the provisions of any law in force in the territory of India into accord with the provisions of this Constitution, the President may ", "p": "XXI", "pn": "Transitional Provisions", "clr": "#80CBC4"}, {"n": "373", "t": "Power of President to make order in respect of persons under preventive", "c": "detention in certain cases:- Until provision is made by Parliament under clause (7) of article 22, or until the expiration of one year from the commencement of this Constitution, whichever is earlier, the said article shall have effect as if for any reference to Parliament in clauses (4) and (7) thereof there were substituted a reference to the President and for any reference to any law made by Parliament in those clauses there were substituted a reference to an order made by the President.", "p": "XXI", "pn": "Transitional Provisions", "clr": "#80CBC4"}, {"n": "374", "t": "Provisions as to Judges of the Federal Court and proceedings pending in the", "c": "Federal Court or before His Majesty in Council:- (1) The Judges of the Federal Court holding office immediately before the commencement of this Constitution shall, unless they have elected otherwise, become on such commencement the Judges of the Supreme Court and shall thereupon be entitled to such salaries and allowances and to such rights in respect of leave of absence and pension as are provided for under article 125 in respect of the Judges of the Supreme Court. (2) All suits, appeals and proceedings, civil or criminal, pending in the Feder", "p": "XXI", "pn": "Transitional Provisions", "clr": "#80CBC4"}, {"n": "375", "t": "Courts, authorities and officers to continue to function subject to the provisions of", "c": "the Constitution:- All courts of civil, criminal and revenue jurisdiction, all authorities and all officers, judicial, executive and ministerial, throughout the territory of India, shall continue to exercise their respective functions subject to the provisions of this Constitution.", "p": "XXI", "pn": "Transitional Provisions", "clr": "#80CBC4"}, {"n": "376", "t": "Provisions as to Judges of High Courts", "c": "(1) Notwithstanding anything in clause (2) of article 217, the Judges of a High Court in any Province holding office immediately before the commencement of this Constitution shall, unless they have elected otherwise, become on such commencement the Judges of the High Court in the corresponding State, and shall thereupon be entitled to such salaries and allowances and to such rights in respect of leave of absence and pension as are provided for under article 221 in respect of the Judges of such High Court. 1[Any such Judge shall, notwithstanding", "p": "XXI", "pn": "Transitional Provisions", "clr": "#80CBC4"}, {"n": "377", "t": "Provisions as to Comptroller and Auditor-General of India.— The Auditor-General", "c": "of India holding office immediately before the commencement of this Constitution shall, unless he has elected otherwise, become on such commencement the Comptroller and Auditor-General of India and shall thereupon be entitled to such salaries and to such rights in respect of leave of absence and pension as are provided for under clause (3) of article 148 in respect of the Comptroller and Auditor-General of India and be entitled to continue to hold office until the expiration of his term of office as determined under the provisions which were ap", "p": "XXI", "pn": "Transitional Provisions", "clr": "#80CBC4"}, {"n": "378", "t": "Provisions as to Public Service Commissions", "c": "(1) The members of the Public Service Commission for the Dominion of India holding office immediately before the commencement of this Constitution shall, unless they have elected otherwise, become on such commencement the members of the Public Service Commission for the Union and shall, notwithstanding anything in clauses (1) and (2) of article 316 but subject to the proviso to clause (2) of that article, continue to hold office until the expiration of their term of office as determined under the rules which were applicable immediately before s", "p": "XXI", "pn": "Transitional Provisions", "clr": "#80CBC4"}, {"n": "392", "t": "Power of the President to remove difficulties", "c": "(1) The President may, for the purpose of removing any difficulties, particularly in relation to the transition from the provisions of the Government of India Act, 1935, to the provisions of this Constitution, by order direct that this Constitution shall, during such period as may be specified in the order, have effect subject to such adaptations, whether by way of modification, addition or omission, as he may deem to be necessary or expedient: Provided that no such order shall be made after the first meeting of Parliament duly constituted unde", "p": "XXI", "pn": "Transitional Provisions", "clr": "#80CBC4"}, {"n": "393", "t": "Short Title", "c": "This Constitution may be called the Constitution of India.", "p": "XXII", "pn": "Short Title & Repeals", "clr": "#CE93D8"}, {"n": "394", "t": "Commencement", "c": "This article and articles 5, 6, 7, 8, 9, 60, 324, 366, 367, 379, 380, 388, 391, 392 and 393 shall come into force at once, and the remaining provisions of this Constitution shall come into force on the twenty-sixth day of January, 1950, which day is referred to in this Constitution as the commencement of this Constitution. [394A. Authoritative text in the Hindi language:- 1) The President shall cause to be published under his authority,— (a) the translation of this Constitution in the Hindi language, signed by the members of the Constituent Ass", "p": "XXII", "pn": "Short Title & Repeals", "clr": "#CE93D8"}, {"n": "395", "t": "Repeals", "c": "The Indian Independence Act, 1947, and the Government of India Act, 1935, together with all enactments amending or supplementing the latter Act, but not including the Abolition of Privy Council Jurisdiction Act, 1949, are hereby repealed.", "p": "XXII", "pn": "Short Title & Repeals", "clr": "#CE93D8"}, {"n": "1996", "t": "Note: Name of enclave in Sl. No. 108 above has been identified as Ashokabari by", "c": "joint ground verification during field season 1996-97. Brig. J.R. Peter Director Land Records & Survey Officio) West Bengal, India & Director, Eastern Circle Survey of India, Calcutta. Md. Shafi Uddin Director General, Land Records (Exand Surveys, Bangladesh. THE CONSTITUTION OF INDIA (Appendix-I) B. EXCHANGEABLE BANGLADESH ENCLAVES IN INDIA WITH AREA Sl. No. Name Chhits of Lying Lying within within Police Police station station Bangladesh W. Bengal A. Enclaves with independent chits J.L. No. Area in acres", "p": "XXII", "pn": "Short Title & Repeals", "clr": "#CE93D8"}];

/* Part color palette — earthy jewel tones to complement ivory bg */
const PART_COLORS = {
  "I":    "#2D5A3D",  "II":   "#3B5E8C",  "III":  "#8B3A2A",
  "IV":   "#5C2D6B",  "IVA":  "#7A5C1E",  "V":    "#1A5C5C",
  "VI":   "#2E5080",  "VII":  "#666050",  "VIII": "#3D5C40",
  "IX":   "#5C3D6B",  "IX/IXA":"#1E5C50","IXA":  "#3A5C30",
  "X":    "#7A4020",  "XI":   "#2A3D7A",  "XII":  "#4A6B2A",
  "XIII": "#7A2A50",  "XIV":  "#2A5C5C",  "XV":   "#8B2A2A",
  "XVI":  "#5C4020",  "XVII": "#1A4A5C",  "XVIII":"#8B3A50",
  "XIX":  "#3D3D3D",  "XX":   "#5C4A20",  "XXI":  "#2A5C40",
  "XXII": "#3D2D5C",
};

const PART_NAMES = {
  "I":"The Union and its Territory","II":"Citizenship","III":"Fundamental Rights",
  "IV":"Directive Principles","IVA":"Fundamental Duties","V":"The Union",
  "VI":"The States","VII":"States in Part B","VIII":"Union Territories",
  "IX":"The Panchayats","IX/IXA":"Panchayats & Municipalities","IXA":"The Municipalities",
  "X":"Scheduled & Tribal Areas","XI":"Union–State Relations","XII":"Finance & Property",
  "XIII":"Trade & Commerce","XIV":"Services","XV":"Elections",
  "XVI":"Special Provisions","XVII":"Official Language","XVIII":"Emergency Provisions",
  "XIX":"Miscellaneous","XX":"Amendment","XXI":"Transitional Provisions","XXII":"Short Title & Repeals"
};

let filtered = [...DATA], activePart = '', curIdx = 0, curView = 'grid';

const PARTS = {};
DATA.forEach(a => { if (!PARTS[a.p]) PARTS[a.p] = { count:0 }; PARTS[a.p].count++; });

/* Populate select */
const sel = document.getElementById('partSel');
Object.keys(PARTS).forEach(p => {
  const o = document.createElement('option');
  o.value = p; o.textContent = 'Part ' + p + ' — ' + (PART_NAMES[p] || p);
  sel.appendChild(o);
});

/* Build sidebar */
function buildSidebar() {
  const sb = document.getElementById('sidebarList');
  sb.innerHTML = '';
  const allBtn = document.createElement('button');
  allBtn.className = 'part-item' + (activePart === '' ? ' active' : '');
  allBtn.id = 'sb-ALL';
  const forestClr = '#2D5A3D';
  allBtn.innerHTML = `<div class="pi-bar" style="background:${forestClr}"></div><div class="pi-inner"><div class="pi-dot" style="background:${forestClr}"></div><div class="pi-text"><div class="pi-part">All Parts</div><div class="pi-name">Complete Constitution</div></div><div class="pi-count">${DATA.length}</div></div>`;
  allBtn.onclick = () => filterByPart('');
  sb.appendChild(allBtn);
  Object.keys(PARTS).forEach(p => {
    const clr = PART_COLORS[p] || '#2D5A3D';
    const btn = document.createElement('button');
    btn.className = 'part-item' + (activePart === p ? ' active' : '');
    btn.id = 'sb-' + p;
    btn.innerHTML = `<div class="pi-bar" style="background:${clr}"></div><div class="pi-inner"><div class="pi-dot" style="background:${clr}"></div><div class="pi-text"><div class="pi-part">Part ${p}</div><div class="pi-name">${PART_NAMES[p] || p}</div></div><div class="pi-count">${PARTS[p].count}</div></div>`;
    btn.onclick = () => filterByPart(p);
    sb.appendChild(btn);
  });
}
buildSidebar();

function filterByPart(p) {
  activePart = p;
  document.getElementById('partSel').value = p;
  buildSidebar();
  const banner = document.getElementById('partBanner');
  if (!p) {
    banner.setAttribute('data-roman', 'ALL');
    banner.style.borderColor = 'var(--c-border2)';
    banner.innerHTML = `<div class="banner-pill" style="background:rgba(45,90,61,0.1);color:var(--c-forest);border-color:rgba(45,90,61,0.25);">All Parts</div><div class="banner-info"><h2>Complete Constitution</h2><p>429 extracted articles across all 22 Parts</p></div>`;
  } else {
    const clr = PART_COLORS[p] || '#2D5A3D';
    banner.setAttribute('data-roman', p);
    banner.style.borderColor = clr + '55';
    banner.style.background = '';
    banner.innerHTML = `<div class="banner-pill" style="background:${clr}18;color:${clr};border-color:${clr}44;">Part ${p}</div><div class="banner-info"><h2>${PART_NAMES[p] || p}</h2><p>${PARTS[p].count} articles in this Part</p></div>`;
  }
  doSearch();
}

function doSearch() {
  const q = document.getElementById('searchInput').value.toLowerCase().trim();
  filtered = DATA.filter(a => {
    if (activePart && a.p !== activePart) return false;
    if (!q) return true;
    return a.n.toLowerCase().includes(q) || a.t.toLowerCase().includes(q) || a.c.toLowerCase().includes(q);
  });
  render(q);
  document.getElementById('resBadge').textContent = filtered.length + ' article' + (filtered.length !== 1 ? 's' : '');
  document.getElementById('noRes').classList.toggle('show', filtered.length === 0);
}

function hl(txt, q) {
  if (!q || !txt) return txt || '';
  return txt.replace(new RegExp('(' + q.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + ')', 'gi'), '<mark>$1</mark>');
}

function render(q = '') {
  document.getElementById('grid').innerHTML = filtered.map((a, i) => {
    const clr = PART_COLORS[a.p] || '#2D5A3D';
    const omit = /omit|repeal/i.test(a.t);
    const prev = a.c ? a.c.substring(0, 180) + (a.c.length > 180 ? '…' : '') : '';
    return `<div class="acard ${omit ? 'omitted' : ''}" style="--card-clr:${clr}" onclick="openModal(${i})">
      <div class="acard-strip" style="background:${clr}"></div>
      <div class="acard-body">
        <div class="acard-top">
          <span class="acard-num" style="background:${clr}15;color:${clr};border-color:${clr}40">${hl(a.n, q)}</span>
          <div class="acard-title">${hl(a.t, q)}</div>
        </div>
        ${prev ? `<div class="acard-preview">${hl(prev, q)}</div>` : ''}
      </div>
      <div class="acard-footer">
        <span class="acard-part-tag">Part ${a.p} · ${a.pn}</span>
        <span class="acard-arrow">→</span>
      </div>
    </div>`;
  }).join('');
}

function setView(v) {
  curView = v;
  document.getElementById('grid').classList.toggle('list', v === 'list');
  document.getElementById('vg').classList.toggle('active', v === 'grid');
  document.getElementById('vl').classList.toggle('active', v === 'list');
}

function openModal(i) {
  curIdx = i;
  const a = filtered[i];
  const clr = PART_COLORS[a.p] || '#2D5A3D';
  document.getElementById('mStrip').style.background = clr;
  document.getElementById('mNum').textContent = 'Article ' + a.n;
  document.getElementById('mNum').style.cssText = `background:${clr}15;color:${clr};border-color:${clr}44;`;
  document.getElementById('mPart').textContent = 'Part ' + a.p + '  ·  ' + a.pn;
  document.getElementById('mPart').style.color = clr;
  document.getElementById('mTitle').textContent = a.t;
  let body = a.c || '';
  if (!body) {
    document.getElementById('mContent').innerHTML = '<div class="modal-empty">Full text not available in this edition.</div>';
  } else {
    body = body.replace(/\((\d+)\)/g, '\n($1)').replace(/\(([a-z])\)/g, '\n($1)').trim();
    document.getElementById('mContent').innerHTML = body.split('\n').filter(Boolean).map(p => `<span class="clause">${p.trim()}</span>`).join('');
  }
  document.getElementById('mPos').textContent = (i + 1) + ' / ' + filtered.length;
  document.getElementById('mPrev').disabled = i === 0;
  document.getElementById('mNext').disabled = i === filtered.length - 1;
  document.getElementById('overlay').classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closeModal() { document.getElementById('overlay').classList.remove('open'); document.body.style.overflow = ''; }
function overlayClick(e) { if (e.target === document.getElementById('overlay')) closeModal(); }
function navModal(d) { const ni = curIdx + d; if (ni >= 0 && ni < filtered.length) openModal(ni); }

document.addEventListener('keydown', e => {
  if (!document.getElementById('overlay').classList.contains('open')) return;
  if (e.key === 'Escape') closeModal();
  if (e.key === 'ArrowLeft') navModal(-1);
  if (e.key === 'ArrowRight') navModal(1);
});
window.addEventListener('scroll', () => {
  document.getElementById('toTop').classList.toggle('vis', scrollY > 400);
});
render();


function googleTranslateElementInit() {
  new google.translate.TranslateElement({
    pageLanguage: 'en',
    // Limit translation to major Indian languages + English
    includedLanguages: 'te,en,hi,ta,mr,bn,gu,kn,ml,or,pa,as,ur,sa,sd,ne',
    layout: google.translate.TranslateElement.InlineLayout.SIMPLE
  }, 'google_translate_element_floating');
}
